import React, { useState, useEffect, useRef } from 'react';
import Editor from '@monaco-editor/react';
import { Maximize2, Minimize2, ZoomIn, ZoomOut, Play, RefreshCw, Code, Eye } from 'lucide-react';

interface CodeEditorEngineProps {
  configStr: string;
}

export const CodeEditorEngine: React.FC<CodeEditorEngineProps> = ({ configStr }) => {
  const [code, setCode] = useState('');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [view, setView] = useState<'split' | 'code' | 'preview'>('split');
  const [fontSize, setFontSize] = useState(14);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => {
    try {
      const parsed = JSON.parse(configStr);
      setCode(parsed.code || '// Write your JS/HTML here\nconsole.log("Hello MathSci IDE!");');
    } catch (e) {
      setCode(configStr);
    }
  }, [configStr]);

  const runCode = () => {
    if (!iframeRef.current) return;
    const iframe = iframeRef.current;
    const doc = iframe.contentDocument || iframe.contentWindow?.document;
    if (!doc) return;

    // Construct a full HTML document from the code
    // If the code doesn't have <html> tags, wrap it.
    const isFullHtml = code.includes('<html') || code.includes('<body');
    const content = isFullHtml ? code : `
      <!DOCTYPE html>
      <html>
        <head>
          <style>
            body { margin: 0; background: #030712; color: #f3f4f6; font-family: sans-serif; overflow: hidden; }
            canvas { display: block; width: 100vw; height: 100vh; }
          </style>
        </head>
        <body>
          <div id="app"></div>
          <script type="module">
            try {
              ${code}
            } catch (err) {
              document.body.innerHTML = '<pre style="color: #f87171; padding: 20px;">' + err.stack + '</pre>';
            }
          </script>
        </body>
      </html>
    `;

    doc.open();
    doc.write(content);
    doc.close();
  };

  useEffect(() => {
    const timer = setTimeout(runCode, 1000);
    return () => clearTimeout(timer);
  }, [code]);

  const toggleFullscreen = () => setIsFullscreen(!isFullscreen);

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed',
    inset: 0,
    zIndex: 9999,
    backgroundColor: 'var(--bg-main)',
    display: 'flex',
    flexDirection: 'column',
  } : {
    position: 'relative',
    backgroundColor: 'var(--bg-sidebar)',
    borderRadius: '0.5rem',
    border: '1px solid var(--border-color)',
    height: '500px',
    width: '100%',
    display: 'flex',
    flexDirection: 'column',
    overflow: 'hidden',
    margin: '1rem 0'
  };

  return (
    <div style={containerStyle} className="group">
      {/* Toolbar */}
      <div style={{ 
        padding: '0.5rem 1rem', 
        borderBottom: '1px solid var(--border-color)', 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        background: 'rgba(0,0,0,0.2)'
      }}>
        <div style={{ display: 'flex', gap: '0.5rem' }}>
          <button onClick={() => setView('code')} className={`btn-icon ${view==='code'?'text-[var(--accent-color)]':''}`} title="Code Only"><Code size={16}/></button>
          <button onClick={() => setView('split')} className={`btn-icon ${view==='split'?'text-[var(--accent-color)]':''}`} title="Split View"><Maximize2 size={16} style={{transform: 'rotate(45deg)'}}/></button>
          <button onClick={() => setView('preview')} className={`btn-icon ${view==='preview'?'text-[var(--accent-color)]':''}`} title="Preview Only"><Eye size={16}/></button>
        </div>

        <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
          <button onClick={() => setFontSize(s => Math.max(8, s-1))} className="btn-icon" title="Zoom Out"><ZoomOut size={16}/></button>
          <span style={{ fontSize: '10px', opacity: 0.5, fontFamily: 'monospace' }}>{fontSize}px</span>
          <button onClick={() => setFontSize(s => Math.min(30, s+1))} className="btn-icon" title="Zoom In"><ZoomIn size={16}/></button>
          <div style={{ width: '1px', height: '16px', background: 'var(--border-color)', margin: '0 0.25rem' }} />
          <button onClick={runCode} className="btn-icon text-green-500" title="Run Code"><Play size={16}/></button>
          <button onClick={toggleFullscreen} className="btn-icon">
            {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
          </button>
        </div>
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {(view === 'code' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', borderRight: view === 'split' ? '1px solid var(--border-color)' : 'none' }}>
            <Editor
              height="100%"
              defaultLanguage="javascript"
              theme="vs-dark"
              value={code}
              onChange={(v) => setCode(v || '')}
              options={{
                fontSize: fontSize,
                minimap: { enabled: false },
                scrollBeyondLastLine: false,
                automaticLayout: true,
                padding: { top: 10 }
              }}
            />
          </div>
        )}
        {(view === 'preview' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', background: '#000', position: 'relative' }}>
            <iframe
              ref={iframeRef}
              title="IDE Preview"
              style={{ width: '100%', height: '100%', border: 'none' }}
              sandbox="allow-scripts allow-modals"
            />
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { Edit3, Columns, Eye } from 'lucide-react';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';

interface EditorProps {
  content: string;
  fileName: string;
  onChange: (content: string) => void;
  readOnly?: boolean;
}

export const Editor: React.FC<EditorProps> = ({ content, fileName, onChange, readOnly = false }) => {
  const [view, setView] = useState<'split' | 'editor' | 'preview'>('split');
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const markdownComponents = useMemo(() => ({
    a: ({node, ...props}: any) => <a {...props} target="_blank" rel="noopener noreferrer" />,

    img: ({ src, alt }: any) => {
      if (!src) return null;
      return (
        <img
          src={src}
          alt={alt || ''}
          style={{ maxWidth: '100%' }}
          loading="lazy"
        />
      );
    },

    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={String(children).replace(/\n$/, '')} />;
            case 'smiles': return <SmilesDiagram smiles={String(children).replace(/\n$/, '')} />;
            case 'plot': return <InteractivePlot configStr={String(children).replace(/\n$/, '')} />;
            case 'physics': return <PhysicsSimulation configStr={String(children).replace(/\n$/, '')} />;
            case 'ide': return <CodeEditorEngine configStr={String(children).replace(/\n$/, '')} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    },
    'model-viewer': ({node, ...props}: any) => <model-viewer {...props}></model-viewer>,
    div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
    span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
  }), []);

  const insertFormat = (prefix: string, suffix: string = '', blockMode: boolean = false) => {
    if (!textareaRef.current || readOnly) return;
    const { selectionStart: start, selectionEnd: end, value: text } = textareaRef.current;
    const selected = text.substring(start, end);
    let newText = '', newCursor = 0;

    if (blockMode) {
        const hasNewline = text.substring(0, start).endsWith('\n') || start === 0;
        newText = `${text.substring(0, start)}${hasNewline ? '' : '\n'}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + (hasNewline ? 0 : 1) + selected.length;
    } else {
        newText = `${text.substring(0, start)}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + selected.length;
    }
    onChange(newText);
    setTimeout(() => { textareaRef.current?.focus(); textareaRef.current?.setSelectionRange(newCursor, newCursor); }, 0);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const { selectionStart: start, selectionEnd: end, value } = e.currentTarget;
      onChange(value.substring(0, start) + '  ' + value.substring(end));
      setTimeout(() => { if(textareaRef.current) textareaRef.current.selectionStart = textareaRef.current.selectionEnd = start + 2; }, 0);
    }
  };

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        <div className="h-10 flex items-center justify-between px-4 border-b border-[var(--border-color)]">
             <div className="text-sm flex items-center gap-2"><span className="font-medium font-mono text-[var(--accent-color)]">{fileName}</span>{readOnly && <span className="text-xs px-2 py-0.5 rounded bg-[var(--bg-sidebar)] text-[var(--text-muted)]">Read Only</span>}</div>
            <div className="flex rounded p-0.5 bg-[var(--bg-main)]">
                {['editor', 'split', 'preview'].map((v: any) => (
                    <button key={v} onClick={() => setView(v)} className={`p-1.5 rounded transition-colors ${view===v ? 'bg-[var(--accent-color)] text-white' : 'text-[var(--text-muted)]'} ${v==='split'?'md-visible hidden':''}`}>
                        {v==='editor' ? <Edit3 size={14}/> : v==='split' ? <Columns size={14}/> : <Eye size={14}/>}
                    </button>
                ))}
            </div>
        </div>
        {(view !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(view === 'split' || view === 'editor') && (
            <div className={`pane ${view === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={content} 
                  onChange={e => onChange(e.target.value)} 
                  onKeyDown={handleKeyDown} 
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                  style={{
                    width: '100%',
                    height: '100%',
                    padding: '8px',
                    fontFamily: 'monospace',
                    border: '1px solid var(--border-color)',
                    resize: 'none',
                    overflowX: 'auto',
                    whiteSpace: 'pre-wrap',
                    wordBreak: 'break-all',
                    boxSizing: 'border-box',
                  }}
                />
            </div>
        )}
        {(view === 'split' || view === 'preview') && (
            <div id="markdown-preview" className={`pane ${view === 'split' ? 'half' : 'full'} preview-area`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents}
                        urlTransform={(url) => url}
                        remarkRehypeOptions={{ handlers: { math: (s:any, n:any) => ({ type: 'element', tagName: 'div', properties: { className: ['math-display'], 'data-math': n.value }, children: [] }), inlineMath: (s:any, n:any) => ({ type: 'element', tagName: 'span', properties: { className: ['math-inline'], 'data-math': n.value }, children: [] }) }}}
                    >{content}</ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

