          alt={alt || ''}
          style={{ maxWidth: '100%' }}
          loading="lazy"
        />
      );
    },

    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={String(children).replace(/\n$/, '')} />;
            case 'smiles': return <SmilesDiagram smiles={String(children).replace(/\n$/, '')} />;
            case 'plot': return <InteractivePlot configStr={String(children).replace(/\n$/, '')} />;
            case 'physics': return <PhysicsSimulation configStr={String(children).replace(/\n$/, '')} />;
            case 'ide': return <CodeEditorEngine configStr={String(children).replace(/\n$/, '')} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    },
    // Fix: Using a string for the custom element name to avoid JSX property lookup errors
    'model-viewer': ({node, ...props}: any) => React.createElement('model-viewer', props),
    div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
    span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
  }), []);

  const insertFormat = (prefix: string, suffix: string = '', blockMode: boolean = false) => {
    if (!textareaRef.current || readOnly) return;
    const { selectionStart: start, selectionEnd: end, value: text } = textareaRef.current;
    const selected = text.substring(start, end);
    let newText = '', newCursor = 0;

    if (blockMode) {
        const hasNewline = text.substring(0, start).endsWith('\n') || start === 0;
        newText = `${text.substring(0, start)}${hasNewline ? '' : '\n'}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + (hasNewline ? 0 : 1) + selected.length;
    } else {
        newText = `${text.substring(0, start)}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + selected.length;
    }
    onChange(newText);
    setTimeout(() => { textareaRef.current?.focus(); textareaRef.current?.setSelectionRange(newCursor, newCursor); }, 0);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const { selectionStart: start, selectionEnd: end, value } = e.currentTarget;
      onChange(value.substring(0, start) + '  ' + value.substring(end));
      setTimeout(() => { if(textareaRef.current) textareaRef.current.selectionStart = textareaRef.current.selectionEnd = start + 2; }, 0);
    }
  };

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        <div className="h-10 flex items-center justify-between px-4 border-b border-[var(--border-color)]">
             <div className="text-sm flex items-center gap-2"><span className="font-medium font-mono text-[var(--accent-color)]">{fileName}</span>{readOnly && <span className="text-xs px-2 py-0.5 rounded bg-[var(--bg-sidebar)] text-[var(--text-muted)]">Read Only</span>}</div>
            <div className="flex rounded p-0.5 bg-[var(--bg-main)]">
                {['editor', 'split', 'preview'].map((v: any) => (
                    <button key={v} onClick={() => setView(v)} className={`p-1.5 rounded transition-colors ${view===v ? 'bg-[var(--accent-color)] text-white' : 'text-[var(--text-muted)]'} ${v==='split'?'md-visible hidden':''}`}>
                        {v==='editor' ? <Edit3 size={14}/> : v==='split' ? <Columns size={14}/> : <Eye size={14}/>}
                    </button>
                ))}
            </div>
        </div>
        {(view !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(view === 'split' || view === 'editor') && (
            <div className={`pane ${view === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={content} 
                  onChange={e => onChange(e.target.value)} 
                  onKeyDown={handleKeyDown} 
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                  style={{
                    width: '100%',
                    height: '100%',
                    padding: '8px',
                    fontFamily: 'monospace',
                    border: '1px solid var(--border-color)',
                    resize: 'none',
                    overflowX: 'auto',
                    whiteSpace: 'pre-wrap',
                    wordBreak: 'break-all',
                    boxSizing: 'border-box',
                  }}
                />
            </div>
        )}
        {(view === 'split' || view === 'preview') && (
            <div id="markdown-preview" className={`pane ${view === 'split' ? 'half' : 'full'} preview-area`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents}
                        urlTransform={(url) => url}
                        remarkRehypeOptions={{ handlers: { math: (s:any, n:any) => ({ type: 'element', tagName: 'div', properties: { className: ['math-display'], 'data-math': n.value }, children: [] }), inlineMath: (s:any, n:any) => ({ type: 'element', tagName: 'span', properties: { className: ['math-inline'], 'data-math': n.value }, children: [] }) }}}
                    >{content}</ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import Editor from '@monaco-editor/react';
import { Maximize2, Minimize2, ZoomIn, ZoomOut, Play, Code, Eye, FileCode, Hash, Globe, Download } from 'lucide-react';

interface CodeFiles {
  js: string;
  html: string;
  css: string;
  language: 'javascript' | 'typescript';
}

interface CodeEditorEngineProps {
  configStr: string;
}

export const CodeEditorEngine: React.FC<CodeEditorEngineProps> = ({ configStr }) => {
  const [files, setFiles] = useState<CodeFiles>({
    js: '',
    html: '<div id="root"></div>',
    css: 'body { margin: 0; background: #030712; color: #fff; font-family: sans-serif; }',
    language: 'javascript'
  });

  const [activeTab, setActiveTab] = useState<keyof Omit<CodeFiles, 'language'>>('js');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [view, setView] = useState<'split' | 'code' | 'preview'>('split');
  const [fontSize, setFontSize] = useState(14);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => {
    try {
      const parsed = JSON.parse(configStr);
      setFiles({
        js: parsed.js || parsed.code || '// Write your code here',
        html: parsed.html || '<div id="root"></div>',
        css: parsed.css || 'body { margin: 0; background: #030712; }',
        language: parsed.language || (parsed.js?.includes('<') ? 'typescript' : 'javascript')
      });
    } catch (e) {
      setFiles(prev => ({ ...prev, js: configStr }));
    }
  }, [configStr]);

  const generateSource = useMemo(() => {
    const isReact = files.js.includes('React') || files.js.includes('render(') || files.js.includes('<');

    // We use a modular approach: 
    // 1. Inject CSS
    // 2. Inject HTML body
    // 3. Inject scripts (Transpiled if needed)
    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="UTF-8" />
          <style>${files.css}</style>
          ${isReact ? '<script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>' : ''}
        </head>
        <body>
          ${files.html}
          <script type="${isReact ? 'text/babel' : 'module'}" data-presets="react,typescript">
            try {
              ${files.js}
            } catch (err) {
              const errorOverlay = document.createElement('div');
              errorOverlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.85);color:#f87171;padding:2rem;font-family:monospace;z-index:9999;white-space:pre-wrap;';
              errorOverlay.textContent = 'Runtime Error:\\n' + err.stack;
              document.body.appendChild(errorOverlay);
            }
          </script>
        </body>
      </html>
    `;
  }, [files]);

  const runCode = () => {
    if (!iframeRef.current) return;
    const iframe = iframeRef.current;
    const doc = iframe.contentDocument || iframe.contentWindow?.document;
    if (!doc) return;

    doc.open();
    doc.write(generateSource);
    doc.close();
  };

  useEffect(() => {
    const timer = setTimeout(runCode, 800);
    return () => clearTimeout(timer);
  }, [files]);

  const downloadProject = () => {
    const blob = new Blob([generateSource], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'mathsci-ide-export.html';
    a.click();
    URL.revokeObjectURL(url);
  };

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed',
    inset: 0,
    zIndex: 9999,
    backgroundColor: 'var(--bg-main)',
    display: 'flex',
    flexDirection: 'column',
  } : {
    position: 'relative',
    backgroundColor: 'var(--bg-sidebar)',
    borderRadius: '0.6rem',
    border: '1px solid var(--border-color)',
    height: '600px',
    width: '100%',
    display: 'flex',
    flexDirection: 'column',
    overflow: 'hidden',
    margin: '1.5rem 0'
  };

  const tabStyle = (id: string) => ({
    padding: '0.5rem 1rem',
    fontSize: '0.75rem',
    fontWeight: 600,
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    gap: '0.4rem',
    borderRight: '1px solid var(--border-color)',
    backgroundColor: activeTab === id ? 'var(--bg-main)' : 'transparent',
    color: activeTab === id ? 'var(--accent-color)' : 'var(--text-muted)',
    transition: 'all 0.2s ease'
  });

  return (
    <div style={containerStyle}>
      {/* Primary Toolbar */}
      <div style={{ 
        height: '42px', 
        borderBottom: '1px solid var(--border-color)', 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        background: 'var(--bg-sidebar)',
        paddingRight: '0.5rem'
      }}>
        {/* Left Side: Tabs */}
        <div style={{ display: 'flex', height: '100%' }}>
          <button onClick={() => setActiveTab('js')} style={tabStyle('js') as any}>
            <FileCode size={14}/> {files.language === 'typescript' ? 'TSX' : 'JS'}
          </button>
          <button onClick={() => setActiveTab('html')} style={tabStyle('html') as any}>
            <Globe size={14}/> HTML
          </button>
          <button onClick={() => setActiveTab('css')} style={tabStyle('css') as any}>
            <Hash size={14}/> CSS
          </button>
        </div>

        {/* Center: View Controls */}
        <div style={{ display: 'flex', gap: '4px', background: 'rgba(0,0,0,0.2)', padding: '3px', borderRadius: '6px' }}>
          <button onClick={() => setView('code')} className={`btn-icon ${view==='code'?'bg-[var(--accent-color)] text-white':''}`} title="Code Only"><Code size={14}/></button>
          <button onClick={() => setView('split')} className={`btn-icon ${view==='split'?'bg-[var(--accent-color)] text-white':''}`} title="Split View"><Maximize2 size={14} style={{transform: 'rotate(45deg)'}}/></button>
          <button onClick={() => setView('preview')} className={`btn-icon ${view==='preview'?'bg-[var(--accent-color)] text-white':''}`} title="Preview Only"><Eye size={14}/></button>
        </div>

        {/* Right Side: Global Controls */}
        <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '2px' }}>
            <button onClick={() => setFontSize(s => Math.max(8, s-1))} className="btn-icon" title="Zoom Out"><ZoomOut size={14}/></button>
            <span style={{ fontSize: '10px', width: '30px', textAlign: 'center', opacity: 0.5, fontFamily: 'monospace' }}>{fontSize}px</span>
            <button onClick={() => setFontSize(s => Math.min(30, s+1))} className="btn-icon" title="Zoom In"><ZoomIn size={14}/></button>
          </div>
          <div style={{ width: '1px', height: '20px', background: 'var(--border-color)' }} />
          <button onClick={runCode} className="btn-icon text-green-500 hover:bg-green-500/10" title="Run Now (Ctrl+Enter)">
            <Play size={16}/>
          </button>
          <button onClick={downloadProject} className="btn-icon text-blue-400" title="Export HTML">
            <Download size={16}/>
          </button>
          <button onClick={() => setIsFullscreen(!isFullscreen)} className="btn-icon">
            {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
          </button>
        </div>
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {/* Editor Pane */}
        {(view === 'code' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', borderRight: view === 'split' ? '1px solid var(--border-color)' : 'none', position: 'relative' }}>
            <Editor
              height="100%"
              language={activeTab === 'js' ? files.language : activeTab}
              theme="vs-dark"
              value={files[activeTab]}
              onChange={(v) => setFiles(prev => ({ ...prev, [activeTab]: v || '' }))}
              options={{
                fontSize: fontSize,
                minimap: { enabled: false },
                scrollBeyondLastLine: false,
                automaticLayout: true,
                padding: { top: 10 },
                lineNumbersMinChars: 3,
                wordWrap: 'on'
              }}
            />
          </div>
        )}

        {/* Preview Pane */}
        {(view === 'preview' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', background: '#000', position: 'relative' }}>
            <iframe
              ref={iframeRef}
              title="IDE Preview"
              style={{ width: '100%', height: '100%', border: 'none', background: '#fff' }}
              sandbox="allow-scripts allow-modals allow-forms allow-popups allow-presentation"
            />
            {/* Status Indicator */}
            <div style={{ 
              position: 'absolute', 
              bottom: '10px', 
              right: '10px', 
              fontSize: '10px', 
              color: 'rgba(0,0,0,0.4)', 
              background: 'rgba(255,255,255,0.7)',
              padding: '2px 6px',
              borderRadius: '4px',
              pointerEvents: 'none'
            }}>
              Sandbox Active
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

