import React, { useState, useEffect, useRef, useMemo } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, ZoomIn, ZoomOut, Play, 
  Code, Eye, FileCode, Hash, Globe, Download, 
  Terminal, Columns, RotateCcw
} from 'lucide-react';

interface CodeFiles {
  js: string;
  html: string;
  css: string;
  language: 'javascript' | 'typescript';
}

interface CodeEditorEngineProps {
  configStr: string;
}

export const CodeEditorEngine: React.FC<CodeEditorEngineProps> = ({ configStr }) => {
  const [files, setFiles] = useState<CodeFiles>({
    js: '',
    html: '<div id="app"></div>',
    css: 'body { margin: 0; background: #0f172a; color: white; display: flex; align-items: center; justify-content: center; height: 100vh; font-family: sans-serif; }',
    language: 'javascript'
  });

  const [activeTab, setActiveTab] = useState<keyof Omit<CodeFiles, 'language'>>('js');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [view, setView] = useState<'split' | 'code' | 'preview'>('split');
  const [fontSize, setFontSize] = useState(14);
  const [isCompiling, setIsCompiling] = useState(false);

  const iframeRef = useRef<HTMLIFrameElement>(null);
  const editorRef = useRef<any>(null);
  const isSyncingRef = useRef(false);

  useEffect(() => {
    try {
      const parsed = JSON.parse(configStr);
      setFiles({
        js: parsed.js || parsed.code || '// Logic here',
        html: parsed.html || '<div id="app"></div>',
        css: parsed.css || 'body { margin: 0; }',
        language: parsed.language || (parsed.js?.includes('<') ? 'typescript' : 'javascript')
      });
    } catch (e) {
      setFiles(prev => ({ ...prev, js: configStr }));
    }
  }, [configStr]);

  const generateSource = useMemo(() => {
    const isReact = files.js.includes('React') || files.js.includes('<');
    const isAngular = files.js.includes('@angular') || files.html.includes('app-root');

    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="UTF-8" />
          <style>${files.css}</style>
          ${isReact ? '<script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>' : ''}
          ${isAngular ? '<script src="https://unpkg.com/zone.js"></script>' : ''}
        </head>
        <body>
          ${files.html}
          <script type="${isReact ? 'text/babel' : 'module'}" data-presets="react,typescript">
            try {
              ${files.js}
            } catch (err) {
              document.body.innerHTML += \`<div style="position:fixed;top:0;left:0;width:100%;background:#f87171;color:white;padding:1rem;font-family:monospace;z-index:9999">\${err.message}</div>\`;
            }
          </script>
        </body>
      </html>
    `;
  }, [files]);

  const runCode = () => {
    if (!iframeRef.current) return;
    setIsCompiling(true);
    const iframe = iframeRef.current;
    const doc = iframe.contentDocument || iframe.contentWindow?.document;
    if (!doc) return;
    doc.open();
    doc.write(generateSource);
    doc.close();
    setTimeout(() => setIsCompiling(false), 300);
  };

  useEffect(() => {
    const timer = setTimeout(runCode, 1000);
    return () => clearTimeout(timer);
  }, [files]);

  // Sync scroll logic
  const handleEditorScroll = (params: any) => {
    if (isSyncingRef.current || view !== 'split' || !iframeRef.current) return;
    isSyncingRef.current = true;
    const scrollPercent = params.scrollTop / (params.scrollHeight - params.clientHeight);
    const iframeWindow = iframeRef.current.contentWindow;
    if (iframeWindow) {
      const targetY = scrollPercent * (iframeWindow.document.documentElement.scrollHeight - iframeWindow.innerHeight);
      iframeWindow.scrollTo(0, targetY);
    }
    setTimeout(() => { isSyncingRef.current = false; }, 50);
  };

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed', inset: 0, zIndex: 9999, backgroundColor: 'var(--bg-main)',
    display: 'flex', flexDirection: 'column'
  } : {
    position: 'relative', backgroundColor: 'var(--bg-sidebar)', borderRadius: '8px',
    border: '1px solid var(--border-color)', height: '550px', width: '100%',
    display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1.5rem 0'
  };

  const tabStyle = (id: string) => ({
    padding: '0 1rem', height: '100%', fontSize: '11px', fontWeight: 700,
    cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px',
    borderRight: '1px solid var(--border-color)',
    backgroundColor: activeTab === id ? 'var(--bg-main)' : 'rgba(0,0,0,0.15)',
    color: activeTab === id ? 'var(--accent-color)' : 'var(--text-muted)',
    borderBottom: activeTab === id ? '2px solid var(--accent-color)' : 'none',
  });

  return (
    <div style={containerStyle}>
      {/* Refined IDE Header */}
      <div style={{ height: '40px', borderBottom: '1px solid var(--border-color)', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: 'var(--bg-sidebar)' }}>
        <div style={{ display: 'flex', height: '100%' }}>
          <button onClick={() => setActiveTab('js')} style={tabStyle('js') as any}><FileCode size={14}/> JS / TS</button>
          <button onClick={() => setActiveTab('html')} style={tabStyle('html') as any}><Globe size={14}/> HTML</button>
          <button onClick={() => setActiveTab('css')} style={tabStyle('css') as any}><Hash size={14}/> CSS</button>
        </div>

        <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center', paddingRight: '0.5rem' }}>
          <div style={{ display: 'flex', gap: '2px', background: 'rgba(0,0,0,0.2)', padding: '2px', borderRadius: '4px', marginRight: '8px' }}>
             <button onClick={() => setView('code')} className={`btn-icon ${view==='code'?'text-[var(--accent-color)]':''}`}><Code size={14}/></button>
             <button onClick={() => setView('split')} className={`btn-icon ${view==='split'?'text-[var(--accent-color)]':''}`}><Columns size={14}/></button>
             <button onClick={() => setView('preview')} className={`btn-icon ${view==='preview'?'text-[var(--accent-color)]':''}`}><Eye size={14}/></button>
          </div>
          <button onClick={runCode} className="btn" style={{ background: '#10b981', color: 'white', border: 'none', height: '28px', padding: '0 10px' }}>
            <Play size={12} fill="currentColor"/> Run
          </button>
          <button onClick={() => setIsFullscreen(!isFullscreen)} className="btn-icon">
            {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
          </button>
        </div>
      </div>

      {/* Viewport Area */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {(view === 'code' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', borderRight: view === 'split' ? '1px solid var(--border-color)' : 'none' }}>
            <Editor
              height="100%"
              theme="vs-dark"
              language={activeTab === 'js' ? files.language : activeTab}
              value={files[activeTab]}
              onChange={(v) => setFiles(prev => ({ ...prev, [activeTab]: v || '' }))}
              onMount={(editor) => {
                editorRef.current = editor;
                editor.onDidScrollChange(handleEditorScroll);
              }}
              options={{
                fontSize, minimap: { enabled: false }, automaticLayout: true,
                padding: { top: 12 }, lineNumbersMinChars: 3, wordWrap: 'on'
              }}
            />
          </div>
        )}
        {(view === 'preview' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', background: '#fff' }}>
            <iframe
              ref={iframeRef}
              style={{ width: '100%', height: '100%', border: 'none' }}
              sandbox="allow-scripts allow-modals allow-forms allow-popups allow-same-origin"
            />
          </div>
        )}
      </div>

      {/* IDE Status Bar */}
      <div style={{ height: '24px', background: 'var(--accent-color)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 10px', fontSize: '10px', fontWeight: 600 }}>
        <div style={{ display: 'flex', gap: '1rem' }}>
          <span>MODE: {files.language.toUpperCase()}</span>
          {isCompiling && <span>• COMPILING...</span>}
        </div>
        <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
          <button onClick={() => setFontSize(s => Math.max(10, s-1))} style={{ color: 'white', background: 'none', border: 'none', cursor: 'pointer' }}><ZoomOut size={10}/></button>
          <span>{fontSize}px</span>
          <button onClick={() => setFontSize(s => Math.min(24, s+1))} style={{ color: 'white', background: 'none', border: 'none', cursor: 'pointer' }}><ZoomIn size={10}/></button>
        </div>
      </div>
    </div>
  );
};

