      <div style={{ height: '22px', background: 'var(--bg-sidebar)', borderTop: '1px solid var(--border-color)', display: 'flex', alignItems: 'center', padding: '0 10px', fontSize: '10px', color: 'var(--text-muted)' }}>
        <div style={{ display: 'flex', gap: '12px' }}>
          <span style={{ color: 'var(--accent-color)', fontWeight: 700 }}>{files.language.toUpperCase()}</span>
          <span>{view.toUpperCase()} VIEW</span>
          <span>SYNC: ACTIVE</span>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
