} from 'lucide-react';

interface CodeFiles {
  js: string;
  html: string;
  css: string;
  language: 'javascript' | 'typescript';
}

interface CodeEditorEngineProps {
  configStr: string;
  onUpdate?: (newConfig: string) => void;
}

// Use React.memo to prevent unnecessary re-renders when the parent Markdown updates
export const CodeEditorEngine = React.memo(({ configStr, onUpdate }: CodeEditorEngineProps) => {
  const [files, setFiles] = useState<CodeFiles>({
    js: '',
    html: '<div id="app"></div>',
    css: 'body { margin: 0; }',
    language: 'javascript'
  });

  const [activeTab, setActiveTab] = useState<keyof Omit<CodeFiles, 'language'>>('js');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [view, setView] = useState<'split' | 'code' | 'preview'>('split');
  const [fontSize] = useState(14);
  const [isCompiling, setIsCompiling] = useState(false);

  const iframeRef = useRef<HTMLIFrameElement>(null);
  const editorRef = useRef<any>(null);
  const syncTimerRef = useRef<any>(null);
  const lastSyncedConfigRef = useRef<string>(configStr);

  // Sync from Markdown to local state ONLY if the change is external
  useEffect(() => {
    if (configStr === lastSyncedConfigRef.current) return;
    try {
      const parsed = JSON.parse(configStr);
      const newFiles: CodeFiles = {
        js: parsed.js || parsed.code || '// Logic here',
        html: parsed.html || '<div id="app"></div>',
        css: parsed.css || 'body { margin: 0; }',
        language: parsed.language || (parsed.js?.includes('<') ? 'typescript' : 'javascript')
      };
      setFiles(newFiles);
      lastSyncedConfigRef.current = configStr;
    } catch (e) {}
  }, [configStr]);

  const debouncedSyncToMarkdown = useCallback((updatedFiles: CodeFiles) => {
    if (syncTimerRef.current) clearTimeout(syncTimerRef.current);

    syncTimerRef.current = setTimeout(() => {
      if (onUpdate) {
        const jsonStr = JSON.stringify({
          language: updatedFiles.language,
          html: updatedFiles.html,
          css: updatedFiles.css,
          js: updatedFiles.js
        }, null, 2);
        lastSyncedConfigRef.current = jsonStr;
        onUpdate(jsonStr);
      }
    }, 1500); // Longer debounce to ensure typing flow is not interrupted
  }, [onUpdate]);

  const handleEditorChange = (value: string | undefined) => {
    const updated = { ...files, [activeTab]: value || '' };
    setFiles(updated);
    debouncedSyncToMarkdown(updated);
  };

  const generateSource = useMemo(() => {
    const isReact = files.js.includes('React') || files.js.includes('<');
    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="UTF-8" />
          <style>
            ${files.css}
            ::-webkit-scrollbar { width: 8px; }
