            ::-webkit-scrollbar-thumb { background: #334155; border-radius: 4px; }
          </style>
          ${isReact ? '<script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>' : ''}
        </head>
        <body style="margin:0; padding:0;">
          ${files.html}
          <script type="${isReact ? 'text/babel' : 'module'}" data-presets="react,typescript">
            try {
              ${files.js}
            } catch (err) {
              const div = document.createElement('div');
              div.style.cssText = "position:fixed;top:0;left:0;width:100%;background:#f87171;color:white;padding:1rem;font-family:monospace;z-index:9999";
              div.textContent = err.message;
              document.body.appendChild(div);
            }
          </script>
        </body>
      </html>
    `;
  }, [files]);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);
    const iframe = iframeRef.current;
    const doc = iframe.contentDocument || iframe.contentWindow?.document;
    if (!doc) return;
    doc.open();
    doc.write(generateSource);
    doc.close();
    setTimeout(() => setIsCompiling(false), 300);
  }, [generateSource]);

  useEffect(() => {
    const timer = setTimeout(runCode, 1000);
    return () => clearTimeout(timer);
  }, [runCode]);

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed', inset: 0, zIndex: 9999, backgroundColor: 'var(--bg-main)',
    display: 'flex', flexDirection: 'column'
  } : {
    position: 'relative', backgroundColor: 'var(--bg-sidebar)', borderRadius: '8px',
    border: '1px solid var(--border-color)', height: '600px', width: '100%',
    display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1.5rem 0'
  };

  const tabStyle = (id: string) => ({
    padding: '0 1rem', height: '100%', fontSize: '11px', fontWeight: 700,
    cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px',
    borderRight: '1px solid var(--border-color)',
    backgroundColor: activeTab === id ? 'var(--bg-main)' : 'transparent',
    color: activeTab === id ? 'var(--accent-color)' : 'var(--text-muted)',
    borderBottom: activeTab === id ? '2px solid var(--accent-color)' : 'none',
    transition: 'all 0.2s ease'
  });

  return (
    <div style={containerStyle}>
      <div style={{ 
        height: '44px', 
        borderBottom: '1px solid var(--border-color)', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between', 
        background: 'var(--bg-sidebar)',
        padding: '0 8px'
      }}>
        <div style={{ display: 'flex', height: '100%' }}>
          <button onClick={() => setActiveTab('js')} style={tabStyle('js') as any}><FileCode size={14}/> TSX / JS</button>
          <button onClick={() => setActiveTab('html')} style={tabStyle('html') as any}><Globe size={14}/> HTML</button>
          <button onClick={() => setActiveTab('css')} style={tabStyle('css') as any}><Hash size={14}/> CSS</button>
        </div>

        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
          <div style={{ display: 'flex', background: 'rgba(0,0,0,0.2)', padding: '2px', borderRadius: '6px' }}>
             <button onClick={() => setView('code')} className="btn-icon" style={{ padding: '4px', color: view === 'code' ? 'var(--accent-color)' : 'inherit' }}><Square size={14}/></button>
             <button onClick={() => setView('split')} className="btn-icon" style={{ padding: '4px', color: view === 'split' ? 'var(--accent-color)' : 'inherit' }}><Columns size={14}/></button>
