    cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px',
    background: activeTab === id ? '#030712' : 'transparent',
    color: activeTab === id ? '#3b82f6' : '#9ca3af',
    border: 'none',
    borderBottom: activeTab === id ? '2px solid #3b82f6' : 'none',
