        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between', 
        background: '#111827',
        padding: '0 12px',
        flexShrink: 0
      }}>
        <div style={{ display: 'flex', height: '100%', gap: '4px' }}>
          <button onClick={() => setActiveTab('js')} style={tabStyle('js') as any}><FileCode size={14}/> TSX / JS</button>
          <button onClick={() => setActiveTab('html')} style={tabStyle('html') as any}><Globe size={14}/> HTML</button>
