import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, 
  Eye, FileCode, Hash, Globe, Columns, Square, Save, RotateCw, File
} from 'lucide-react';

interface CodeFiles {
  js: string;
  html: string;
  css: string;
  singleHtml?: string;
  mode: 'multi' | 'single';
  language: 'javascript' | 'typescript' | 'html';
}

interface IDEState {
  files: CodeFiles;
  isFullscreen: boolean;
  view: 'split' | 'code' | 'preview';
  activeTab: 'js' | 'html' | 'css' | 'singleHtml';
}

interface CodeEditorEngineProps {
  configStr: string;
  onUpdate?: (newConfig: string) => void;
  blockId: string;
}

const ideStateStore: Record<string, IDEState> = {};

export const CodeEditorEngine = React.memo(({ configStr, onUpdate, blockId }: CodeEditorEngineProps) => {
  const [state, setState] = useState<IDEState>(() => {
    if (ideStateStore[blockId]) return ideStateStore[blockId];

    try {
      const parsed = JSON.parse(configStr);
      const isSingle = !!parsed.singleHtml || parsed.mode === 'single';

      let language: 'javascript' | 'typescript' | 'html' = 'javascript';
      if (parsed.language === 'typescript' || parsed.language === 'html') {
        language = parsed.language;
      } else if (isSingle) {
        language = 'html';
      }

      return {
        files: {
          js: parsed.js || parsed.code || '',
          html: parsed.html || '<div id="app"></div>',
          css: parsed.css || 'body { margin: 0; background: #000; overflow: hidden; }',
          singleHtml: parsed.singleHtml || '<!DOCTYPE html>\n<html>\n<head>\n  <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>\n</head>\n<body>\n  <script>\n    console.log("Three.js loaded:", !!window.THREE);\n  </script>\n</body>\n</html>',
          mode: isSingle ? 'single' : 'multi',
          language: language
        },
        isFullscreen: false,
        view: 'split',
        activeTab: isSingle ? 'singleHtml' : 'js'
      };
    } catch (e) {
      return {
        files: { js: '', html: '', css: '', mode: 'multi', language: 'javascript' },
        isFullscreen: false,
        view: 'split',
        activeTab: 'js'
      };
    }
  });

  const { files, isFullscreen, view, activeTab } = state;
  const [isCompiling, setIsCompiling] = useState(false);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);

  const iframeRef = useRef<HTMLIFrameElement>(null);
  const isInternalUpdate = useRef(false);

  useEffect(() => {
    ideStateStore[blockId] = state;
  }, [state, blockId]);

  const syncToMarkdown = useCallback((currentFiles: CodeFiles) => {
    if (onUpdate) {
      isInternalUpdate.current = true;
      onUpdate(JSON.stringify(currentFiles, null, 2));
      setHasUnsavedChanges(false);
    }
  }, [onUpdate]);

  const handleEditorChange = (value: string | undefined) => {
    setState(prev => ({
      ...prev,
      files: { ...prev.files, [activeTab]: value || '' }
    }));
    setHasUnsavedChanges(true);
  };

  const generateSource = useMemo(() => {
    if (files.mode === 'single') return files.singleHtml || '';

    const jsContent = files.js;
    const needsThree = jsContent.includes('THREE') || jsContent.includes('three');
    const needsBabylon = jsContent.includes('BABYLON') || jsContent.includes('Babylon');
    const isReact = jsContent.includes('React') || jsContent.includes('<');

    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="UTF-8" />
          <meta name="viewport" content="width=device-width, initial-scale=1.0" />
          <style>${files.css} body { margin: 0; padding: 0; height: 100vh; width: 100vw; overflow: hidden; }</style>
          ${isReact ? '<script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>' : ''}
          ${needsThree ? '<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>' : ''}
          ${needsBabylon ? '<script src="https://cdn.babylonjs.com/babylon.js"></script>' : ''}
        </head>
        <body>
          ${files.html}
          <script type="${isReact ? 'text/babel' : 'module'}">
            try { ${jsContent} } catch (err) { console.error("Error:", err); }
          </script>
        </body>
      </html>
    `;
  }, [files]);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);
    syncToMarkdown(files);
    const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
    if (!doc) return;
    doc.open();
    doc.write(generateSource);
    doc.close();
    setTimeout(() => setIsCompiling(false), 500);
  }, [generateSource, files, syncToMarkdown]);

  useEffect(() => {
    const timer = setTimeout(runCode, 500);
    return () => clearTimeout(timer);
  }, []);

  const toggleMode = () => {
    setState(prev => {
      const newMode = prev.files.mode === 'multi' ? 'single' : 'multi';
      return {
        ...prev,
        files: { ...prev.files, mode: newMode },
        activeTab: newMode === 'single' ? 'singleHtml' : 'js'
      };
    });
    setHasUnsavedChanges(true);
  };

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed', inset: 0, zIndex: 10000, backgroundColor: '#030712',
    display: 'flex', flexDirection: 'column'
  } : {
    position: 'relative', backgroundColor: '#111827', borderRadius: '8px',
    border: '1px solid #1f2937', height: '600px', width: '100%',
    display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1.5rem 0'
  };

  return (
    <div style={containerStyle} className="ide-block">
      <div style={{ 
        height: '40px', 
        borderBottom: '1px solid #1f2937', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between', 
        background: '#111827',
        padding: '0 8px',
        flexShrink: 0
      }}>
        <div style={{ display: 'flex', height: '100%', gap: '2px', overflow: 'hidden' }}>
          {files.mode === 'multi' ? (
            (['js', 'html', 'css'] as const).map(tab => (
              <button 
                key={tab}
                onClick={() => setState(p => ({ ...p, activeTab: tab }))} 
                style={{ 
                  padding: '0 10px', 
                  background: activeTab === tab ? '#030712' : 'transparent', 
                  color: activeTab === tab ? '#3b82f6' : '#9ca3af', 
                  border: 'none', 
                  borderBottom: activeTab === tab ? '2px solid #3b82f6' : 'none', 
                  fontSize: '10px', 
                  fontWeight: 700, 
                  cursor: 'pointer', 
                  display: 'flex', 
                  alignItems: 'center', 
                  gap: '4px' 
                }}
              >
                {tab === 'js' ? <FileCode size={12}/> : tab === 'html' ? <Globe size={12}/> : <Hash size={12}/>}
                {tab.toUpperCase()}
              </button>
            ))
          ) : (
            <button 
              onClick={() => setState(p => ({ ...p, activeTab: 'singleHtml' }))} 
              style={{ padding: '0 10px', background: '#030712', color: '#3b82f6', border: 'none', borderBottom: '2px solid #3b82f6', fontSize: '10px', fontWeight: 700, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px' }}
            >
              <File size={12}/> INDEX.HTML
            </button>
          )}
        </div>

        <div style={{ display: 'flex', gap: '6px', alignItems: 'center', flexShrink: 0 }}>
          <button 
            onClick={toggleMode} 
            style={{ fontSize: '9px', padding: '4px 6px', background: 'rgba(59, 130, 246, 0.1)', color: '#3b82f6', border: '1px solid rgba(59, 130, 246, 0.2)', borderRadius: '4px', cursor: 'pointer', fontWeight: 600 }}
          >
            {files.mode === 'multi' ? 'SINGLE MODE' : 'MULTI MODE'}
          </button>

          <div style={{ display: 'flex', background: 'rgba(0,0,0,0.3)', padding: '2px', borderRadius: '4px', border: '1px solid #1f2937' }}>
             <button onClick={() => setState(p => ({ ...p, view: 'code' }))} style={{ padding: '4px', color: view === 'code' ? '#3b82f6' : '#9ca3af', border: 'none', background: 'transparent', cursor: 'pointer' }}><Square size={14}/></button>
             <button onClick={() => setState(p => ({ ...p, view: 'split' }))} style={{ padding: '4px', color: view === 'split' ? '#3b82f6' : '#9ca3af', border: 'none', background: 'transparent', cursor: 'pointer' }}><Columns size={14}/></button>
             <button onClick={() => setState(p => ({ ...p, view: 'preview' }))} style={{ padding: '4px', color: view === 'preview' ? '#3b82f6' : '#9ca3af', border: 'none', background: 'transparent', cursor: 'pointer' }}><Eye size={14}/></button>
          </div>

          <button 
            onClick={runCode} 
            style={{ background: hasUnsavedChanges ? '#3b82f6' : '#10b981', color: 'white', border: 'none', borderRadius: '4px', height: '28px', padding: '0 10px', fontSize: '10px', fontWeight: 600, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px' }}
          >
            {hasUnsavedChanges ? <Save size={12} /> : <RotateCw size={12} className={isCompiling ? 'animate-spin' : ''} />}
            {hasUnsavedChanges ? 'RUN' : 'REFRESH'}
          </button>

          <button 
            onClick={() => setState(p => ({ ...p, isFullscreen: !isFullscreen }))} 
            style={{ padding: '4px', background: '#1f2937', borderRadius: '4px', color: 'white', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
          </button>
        </div>
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {(view === 'code' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', background: '#1e1e1e', borderRight: view === 'split' ? '1px solid #1f2937' : 'none' }}>
            <Editor
              height="100%"
              theme="vs-dark"
              language={activeTab === 'js' ? files.language : 'html'}
              value={(files as any)[activeTab]}
              onChange={handleEditorChange}
              options={{ fontSize: 13, minimap: { enabled: false }, automaticLayout: true, padding: { top: 12 }, wordWrap: 'on' }}
            />
          </div>
        )}
        {(view === 'preview' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', background: '#000', position: 'relative' }}>
            <iframe ref={iframeRef} title="IDE Preview" style={{ width: '100%', height: '100%', border: 'none' }} sandbox="allow-scripts allow-modals allow-same-origin" />
            {isCompiling && (
              <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'rgba(0,0,0,0.6)', zIndex: 20 }}>
                <RotateCw size={20} className="animate-spin text-blue-500" />
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
});

import React, { useState, useRef, useMemo, useCallback } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[]; // Added to provide access to all project files
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const previewRef = useRef<HTMLDivElement>(null);
  const isSyncingScroll = useRef(false);

  const handleEditorScroll = () => {
    if (isSyncingScroll.current || viewMode !== 'split' || !textareaRef.current || !previewRef.current) return;
    isSyncingScroll.current = true;
    const { scrollTop, scrollHeight, clientHeight } = textareaRef.current;
    const scrollPercent = scrollTop / (scrollHeight - clientHeight);
    const preview = previewRef.current;
    preview.scrollTop = scrollPercent * (preview.scrollHeight - preview.clientHeight);
    setTimeout(() => { isSyncingScroll.current = false; }, 50);
  };

  const handlePreviewScroll = () => {
    if (isSyncingScroll.current || viewMode !== 'split' || !textareaRef.current || !previewRef.current) return;
    isSyncingScroll.current = true;
    const { scrollTop, scrollHeight, clientHeight } = previewRef.current;
    const scrollPercent = scrollTop / (scrollHeight - clientHeight);
    const textarea = textareaRef.current;
    textarea.scrollTop = scrollPercent * (textarea.scrollHeight - textarea.clientHeight);
    setTimeout(() => { isSyncingScroll.current = false; }, 50);
  };

  const handleIDEUpdate = useCallback((oldConfig: string, newConfig: string) => {
    if (oldConfig === newConfig) return;
    const escapedOldConfig = oldConfig.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regex = new RegExp('```ide\\n' + escapedOldConfig + '\\n```', 'g');

    if (regex.test(content)) {
      const updatedContent = content.replace(regex, '```ide\n' + newConfig + '\n```');
      onChange(updatedContent);
    } else if (content.includes(oldConfig)) {
      const updatedContent = content.replace(oldConfig, newConfig);
      onChange(updatedContent);
    }
  }, [content, onChange]);

  const markdownComponents = useMemo(() => ({
    a: ({node, ...props}: any) => <a {...props} target="_blank" rel="noopener noreferrer" />,
    img: ({ src, alt }: any) => {
      if (!src) return null;
      return <img src={src} alt={alt || ''} style={{ maxWidth: '100%' }} loading="lazy" />;
    },
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        const codeContent = String(children).replace(/\n$/, '');
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={codeContent} />;
            case 'smiles': return <SmilesDiagram smiles={codeContent} />;
            case 'plot': return <InteractivePlot configStr={codeContent} />;
            case 'physics': return <PhysicsSimulation configStr={codeContent} />;
            case 'ide': {
              const blockId = `${fileName}-${codeContent.substring(0, 20)}`;
              return (
                <CodeEditorEngine 
                  key={blockId}
                  blockId={blockId}
                  configStr={codeContent} 
                  allFiles={allNodes} // Pass all project files to the IDE
                  onUpdate={(newVal) => handleIDEUpdate(codeContent, newVal)}
                />
              );
            }
          }
        }
        return <code className={className} {...props}>{children}</code>;
    },
    'model-viewer': ({node, ...props}: any) => React.createElement('model-viewer', props),
    div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
    span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
  }), [handleIDEUpdate, fileName, allNodes]);

  const insertFormat = (prefix: string, suffix: string = '', blockMode: boolean = false) => {
    if (!textareaRef.current || readOnly) return;
    const { selectionStart: start, selectionEnd: end, value: text } = textareaRef.current;
    const selected = text.substring(start, end);
    let newText = '', newCursor = 0;
    if (blockMode) {
        const hasNewline = text.substring(0, start).endsWith('\n') || start === 0;
        newText = `${text.substring(0, start)}${hasNewline ? '' : '\n'}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + (hasNewline ? 0 : 1) + selected.length;
    } else {
        newText = `${text.substring(0, start)}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + selected.length;
    }
    onChange(newText);
    setTimeout(() => { textareaRef.current?.focus(); textareaRef.current?.setSelectionRange(newCursor, newCursor); }, 0);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const { selectionStart: start, selectionEnd: end, value } = e.currentTarget;
      onChange(value.substring(0, start) + '  ' + value.substring(end));
      setTimeout(() => { if(textareaRef.current) textareaRef.current.selectionStart = textareaRef.current.selectionEnd = start + 2; }, 0);
    }
  };

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>

      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={content} 
                  onChange={e => onChange(e.target.value)} 
                  onKeyDown={handleKeyDown}
                  onScroll={handleEditorScroll}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div 
              ref={previewRef}
              onScroll={handlePreviewScroll}
              id="markdown-preview" 
              className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}
            >
                <div className="markdown-body">
                    <ReactMarkdown 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents}
                        urlTransform={(url) => url}
                        remarkRehypeOptions={{ 
                          handlers: { 
                            math: (s:any, n:any) => ({ type: 'element', tagName: 'div', properties: { className: ['math-display'], 'data-math': n.value }, children: [] }), 
                            inlineMath: (s:any, n:any) => ({ type: 'element', tagName: 'span', properties: { className: ['math-inline'], 'data-math': n.value }, children: [] }) 
                          } 
                        }}
                    >
                      {content}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, 
  Upload, 
  FileJson, 
  Settings, 
  X,
  Palette,
  PanelLeft,
  FileText,
  ExternalLink,
  Check,
  Edit3,
  Columns,
  Eye
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, ImportData, AppTheme } from './types';
import { initialNodes } from './initialData';
import * as workspaceClient from './utils/workspaceClient';

const themes: Record<string, AppTheme> = {
  dark: {
    name: 'Dark',
    bgMain: '#030712', 
    bgSidebar: '#111827',
    textMain: '#f3f4f6', 
    textMuted: '#9ca3af', 
    border: '#1f2937', 
    accent: '#3b82f6', 
    hover: 'rgba(255, 255, 255, 0.05)'
  },
  light: {
    name: 'Light',
    bgMain: '#ffffff',
    bgSidebar: '#f3f4f6',
    textMain: '#111827',
    textMuted: '#6b7280',
    border: '#e5e7eb',
    accent: '#3b82f6', 
    hover: 'rgba(0, 0, 0, 0.05)'
  },
  navy: {
    name: 'Navy',
    bgMain: '#0a192f',
    bgSidebar: '#112240',
    textMain: '#ccd6f6',
    textMuted: '#8892b0',
    border: '#233554',
    accent: '#64ffda',
    hover: 'rgba(100, 255, 218, 0.1)'
  },
  dracula: {
    name: 'Dracula',
    bgMain: '#282a36',
    bgSidebar: '#21222c',
    textMain: '#f8f8f2',
    textMuted: '#6272a4',
    border: '#44475a',
    accent: '#ff79c6',
    hover: 'rgba(255, 255, 255, 0.1)'
  }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');

  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
  }, [nodes]);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      const remote = await workspaceClient.fetchWorkspace();
      if (!cancelled && remote && Array.isArray(remote.nodes) && remote.nodes.length > 0) {
        setNodes(remote.nodes);
        setActiveFileId(remote.nodes.find(n => n.type === NodeType.FILE)?.id || null);
      }
    })();
    return () => { cancelled = true; };
  }, []);

  const activeNode = nodes.find(n => n.id === activeFileId);

  const exportToJson = () => {
    const data: ImportData = { version: 1, nodes };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mathsci-backup.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importFromJson = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string) as ImportData;
        if (data.nodes) {
          setNodes(data.nodes);
          setActiveFileId(data.nodes.find(n => n.type === NodeType.FILE)?.id || null);
        }
      } catch (err) {
        alert("Invalid workspace file.");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const exportToPdf = () => {
    const element = document.getElementById('markdown-preview');
    if (!element) return;
    const opt = {
      margin: 10,
      filename: `${activeNode?.name || 'document'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };
    window.html2pdf().from(element).set(opt).save();
  };

  return (
    <div className="app-container">
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                const node = { id, parentId, name: 'Untitled.md', type: NodeType.FILE, content: '', createdAt: Date.now() } as FileNode;
                setNodes(prev => [...prev, node]);
                setActiveFileId(id);
            }}
            onAddFolder={(parentId) => {
                const node = { id: uuidv4(), parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() } as FileNode;
                setNodes(prev => [...prev, node]);
            }}
            onDeleteNode={(id) => {
                setNodes(prev => prev.filter(n => n.id !== id));
                if (activeFileId === id) setActiveFileId(null);
            }}
            onRenameNode={(id, name) => {
                setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n));
            }}
            onMoveNode={(id, parentId) => {
                setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n));
            }}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon">
                  <PanelLeft size={18} />
                </button>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <h1 className="app-title">MathSci</h1>
                </div>
            </div>

            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={() => setShowSettings(true)} className="btn">
                    <Palette size={14} /> Theme
                </button>
                <div className="divider"></div>
                <button onClick={exportToPdf} className="btn"><Download size={14} style={{ color: '#f87171' }}/> PDF</button>
                <label className="btn" style={{ cursor: 'pointer' }}>
                    <Upload size={14} style={{ color: '#4ade80' }}/> Import
                    <input type="file" accept=".json" style={{ display: 'none' }} onChange={importFromJson}/>
                </label>
                <button onClick={exportToJson} className="btn"><FileJson size={14} style={{ color: '#facc15' }}/> Backup</button>

                <div className="divider"></div>
                <div style={{ display: 'flex', background: 'var(--bg-main)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px', gap: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ padding: '4px', borderRadius: '4px', background: editorView === 'editor' ? 'var(--hover-bg)' : 'transparent', color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ padding: '4px', borderRadius: '4px', background: editorView === 'split' ? 'var(--hover-bg)' : 'transparent', color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ padding: '4px', borderRadius: '4px', background: editorView === 'preview' ? 'var(--hover-bg)' : 'transparent', color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeNode ? (
                <Editor 
                    content={activeNode.content} 
                    fileName={activeNode.name}
                    allNodes={nodes} // Pass nodes here
                    viewMode={editorView}
                    onChange={(content) => {
                      setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n));
                    }} 
                />
            ) : (
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', color: 'var(--text-muted)' }}>
                    <p>Select a file from the explorer</p>
                </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay">
              <div className="modal" style={{ maxWidth: '400px', background: '#0f172a', color: '#f8fafc', border: '1px solid #1e293b' }}>
                  <div className="modal-header" style={{ borderBottom: '1px solid #1e293b', padding: '1rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <Palette size={18} color="#3b82f6" />
                        <span style={{ fontSize: '1rem', fontWeight: 600 }}>Theme Settings</span>
                      </div>
                      <button onClick={() => setShowSettings(false)} className="btn-icon"><X size={20}/></button>
                  </div>
                  <div className="modal-body" style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                      <div>
                        <label style={{ fontSize: '0.8rem', color: '#94a3b8', marginBottom: '0.75rem', display: 'block' }}>Presets</label>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem' }}>
                            {Object.entries(themes).map(([k, t]) => (
                                <button 
                                    key={k} 
                                    onClick={() => setCurrentTheme(t)} 
                                    style={{ 
                                        padding: '0.75rem', 
                                        borderRadius: '6px', 
                                        background: t.bgMain, 
                                        color: t.textMain, 
                                        border: `1px solid ${currentTheme.name === t.name ? '#3b82f6' : '#1e293b'}`,
                                        cursor: 'pointer',
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: '0.5rem',
                                        fontSize: '0.85rem'
                                    }}
                                >
                                    <div style={{ width: 12, height: 12, borderRadius: '50%', background: t.accent }} />
                                    {t.name}
                                </button>
                            ))}
                        </div>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, 
  Eye, FileCode, Hash, Globe, Columns, Square, Save, RotateCw, File, Layers
} from 'lucide-react';
import { FileNode, NodeType } from '../../types';

interface CodeFiles {
  js: string;
  html: string;
  css: string;
  singleHtml?: string;
  mode: 'multi' | 'single';
  language: 'javascript' | 'typescript' | 'html';
}

interface IDEState {
  files: CodeFiles;
  isFullscreen: boolean;
  view: 'split' | 'code' | 'preview';
  activeTab: 'js' | 'html' | 'css' | 'singleHtml';
}

interface CodeEditorEngineProps {
  configStr: string;
  onUpdate?: (newConfig: string) => void;
  blockId: string;
  allFiles?: FileNode[]; // New prop to receive system files
}

const ideStateStore: Record<string, IDEState> = {};

export const CodeEditorEngine = React.memo(({ configStr, onUpdate, blockId, allFiles = [] }: CodeEditorEngineProps) => {
  const [state, setState] = useState<IDEState>(() => {
    if (ideStateStore[blockId]) return ideStateStore[blockId];

    try {
      const parsed = JSON.parse(configStr);
      const isSingle = !!parsed.singleHtml || parsed.mode === 'single';

      let language: 'javascript' | 'typescript' | 'html' = 'javascript';
      if (parsed.language === 'typescript' || parsed.language === 'html') {
        language = parsed.language;
      } else if (isSingle) {
        language = 'html';
      }

      return {
        files: {
          js: parsed.js || parsed.code || '',
          html: parsed.html || '<div id="app"></div>',
          css: parsed.css || 'body { margin: 0; background: #000; overflow: hidden; }',
          singleHtml: parsed.singleHtml || '<!DOCTYPE html>\n<html>\n<head>\n  <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>\n</head>\n<body>\n  <script>\n    // Use assets["filename"] to access project files\n    console.log("Project Assets Available:", Object.keys(window.assets || {}));\n  </script>\n</body>\n</html>',
          mode: isSingle ? 'single' : 'multi',
          language: language
        },
        isFullscreen: false,
        view: 'split',
        activeTab: isSingle ? 'singleHtml' : 'js'
      };
    } catch (e) {
      return {
        files: { js: '', html: '', css: '', mode: 'multi', language: 'javascript' },
        isFullscreen: false,
        view: 'split',
        activeTab: 'js'
      };
    }
  });

  const { files, isFullscreen, view, activeTab } = state;
  const [isCompiling, setIsCompiling] = useState(false);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);

  const iframeRef = useRef<HTMLIFrameElement>(null);
  const isInternalUpdate = useRef(false);

  useEffect(() => {
    ideStateStore[blockId] = state;
  }, [state, blockId]);

  const syncToMarkdown = useCallback((currentFiles: CodeFiles) => {
    if (onUpdate) {
      isInternalUpdate.current = true;
      onUpdate(JSON.stringify(currentFiles, null, 2));
      setHasUnsavedChanges(false);
    }
  }, [onUpdate]);

  const handleEditorChange = (value: string | undefined) => {
    setState(prev => ({
      ...prev,
      files: { ...prev.files, [activeTab]: value || '' }
    }));
    setHasUnsavedChanges(true);
  };

  // Convert all non-folder files into an asset map script
  const generateAssetScript = useMemo(() => {
    const assetMap: Record<string, string> = {};
    allFiles.forEach(node => {
      if (node.type === NodeType.FILE) {
        assetMap[node.name] = node.content;
      }
    });
    return `window.assets = ${JSON.stringify(assetMap)};`;
  }, [allFiles]);

  const generateSource = useMemo(() => {
    if (files.mode === 'single') {
        const source = files.singleHtml || '';
        // Inject asset script after the first <head> tag
        return source.replace('<head>', `<head><script>${generateAssetScript}</script>`);
    }

    const jsContent = files.js;
    const needsThree = jsContent.includes('THREE') || jsContent.includes('three');
    const needsBabylon = jsContent.includes('BABYLON') || jsContent.includes('Babylon');
    const isReact = jsContent.includes('React') || jsContent.includes('<');

    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="UTF-8" />
          <meta name="viewport" content="width=device-width, initial-scale=1.0" />
          <script>${generateAssetScript}</script>
          <style>${files.css} body { margin: 0; padding: 0; height: 100vh; width: 100vw; overflow: hidden; }</style>
          ${isReact ? '<script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>' : ''}
          ${needsThree ? '<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>' : ''}
          ${needsBabylon ? '<script src="https://cdn.babylonjs.com/babylon.js"></script>' : ''}
        </head>
        <body>
          ${files.html}
          <script type="${isReact ? 'text/babel' : 'module'}">
            try { ${jsContent} } catch (err) { console.error("Error:", err); }
          </script>
        </body>
      </html>
    `;
  }, [files, generateAssetScript]);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);
    syncToMarkdown(files);
    const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
    if (!doc) return;
    doc.open();
    doc.write(generateSource);
    doc.close();
    setTimeout(() => setIsCompiling(false), 500);
  }, [generateSource, files, syncToMarkdown]);

  useEffect(() => {
    const timer = setTimeout(runCode, 500);
    return () => clearTimeout(timer);
  }, []);

  const toggleMode = () => {
    setState(prev => {
      const newMode = prev.files.mode === 'multi' ? 'single' : 'multi';
      return {
        ...prev,
        files: { ...prev.files, mode: newMode },
        activeTab: newMode === 'single' ? 'singleHtml' : 'js'
      };
    });
    setHasUnsavedChanges(true);
  };

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed', inset: 0, zIndex: 10000, backgroundColor: '#030712',
    display: 'flex', flexDirection: 'column'
  } : {
    position: 'relative', backgroundColor: '#111827', borderRadius: '8px',
    border: '1px solid #1f2937', height: '600px', width: '100%',
    display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1.5rem 0'
  };

  const assetCount = useMemo(() => allFiles.filter(n => n.type === NodeType.FILE).length, [allFiles]);

  return (
    <div style={containerStyle} className="ide-block">
      <div style={{ 
        height: '40px', 
        borderBottom: '1px solid #1f2937', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between', 
        background: '#111827',
        padding: '0 8px',
        flexShrink: 0
      }}>
        <div style={{ display: 'flex', height: '100%', gap: '2px', overflow: 'hidden' }}>
          {files.mode === 'multi' ? (
            (['js', 'html', 'css'] as const).map(tab => (
              <button 
                key={tab}
                onClick={() => setState(p => ({ ...p, activeTab: tab }))} 
                style={{ 
                  padding: '0 10px', 
                  background: activeTab === tab ? '#030712' : 'transparent', 
                  color: activeTab === tab ? '#3b82f6' : '#9ca3af', 
                  border: 'none', 
                  borderBottom: activeTab === tab ? '2px solid #3b82f6' : 'none', 
                  fontSize: '10px', 
                  fontWeight: 700, 
                  cursor: 'pointer', 
                  display: 'flex', 
                  alignItems: 'center', 
                  gap: '4px' 
                }}
              >
                {tab === 'js' ? <FileCode size={12}/> : tab === 'html' ? <Globe size={12}/> : <Hash size={12}/>}
                {tab.toUpperCase()}
              </button>
            ))
          ) : (
            <button 
              onClick={() => setState(p => ({ ...p, activeTab: 'singleHtml' }))} 
              style={{ padding: '0 10px', background: '#030712', color: '#3b82f6', border: 'none', borderBottom: '2px solid #3b82f6', fontSize: '10px', fontWeight: 700, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px' }}
            >
              <File size={12}/> INDEX.HTML
            </button>
          )}
        </div>

        <div style={{ display: 'flex', gap: '6px', alignItems: 'center', flexShrink: 0 }}>
          {/* Asset Indicator */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '9px', background: '#1e293b', padding: '4px 8px', borderRadius: '4px', color: '#94a3b8', border: '1px solid #334155' }} title="Available project files in code">
            <Layers size={10} />
            <span style={{ fontWeight: 700, color: assetCount > 0 ? '#3b82f6' : 'inherit' }}>{assetCount} ASSETS</span>
          </div>

          <button 
            onClick={toggleMode} 
            style={{ fontSize: '9px', padding: '4px 6px', background: 'rgba(59, 130, 246, 0.1)', color: '#3b82f6', border: '1px solid rgba(59, 130, 246, 0.2)', borderRadius: '4px', cursor: 'pointer', fontWeight: 600 }}
          >
            {files.mode === 'multi' ? 'SINGLE MODE' : 'MULTI MODE'}
          </button>

          <div style={{ display: 'flex', background: 'rgba(0,0,0,0.3)', padding: '2px', borderRadius: '4px', border: '1px solid #1f2937' }}>
             <button onClick={() => setState(p => ({ ...p, view: 'code' }))} style={{ padding: '4px', color: view === 'code' ? '#3b82f6' : '#9ca3af', border: 'none', background: 'transparent', cursor: 'pointer' }}><Square size={14}/></button>
             <button onClick={() => setState(p => ({ ...p, view: 'split' }))} style={{ padding: '4px', color: view === 'split' ? '#3b82f6' : '#9ca3af', border: 'none', background: 'transparent', cursor: 'pointer' }}><Columns size={14}/></button>
             <button onClick={() => setState(p => ({ ...p, view: 'preview' }))} style={{ padding: '4px', color: view === 'preview' ? '#3b82f6' : '#9ca3af', border: 'none', background: 'transparent', cursor: 'pointer' }}><Eye size={14}/></button>
          </div>

          <button 
            onClick={runCode} 
            style={{ background: hasUnsavedChanges ? '#3b82f6' : '#10b981', color: 'white', border: 'none', borderRadius: '4px', height: '28px', padding: '0 10px', fontSize: '10px', fontWeight: 600, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px' }}
          >
            {hasUnsavedChanges ? <Save size={12} /> : <RotateCw size={12} className={isCompiling ? 'animate-spin' : ''} />}
            {hasUnsavedChanges ? 'RUN' : 'REFRESH'}
          </button>

          <button 
            onClick={() => setState(p => ({ ...p, isFullscreen: !isFullscreen }))} 
            style={{ padding: '4px', background: '#1f2937', borderRadius: '4px', color: 'white', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
          </button>
        </div>
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {(view === 'code' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', background: '#1e1e1e', borderRight: view === 'split' ? '1px solid #1f2937' : 'none' }}>
            <Editor
              height="100%"
              theme="vs-dark"
              language={activeTab === 'js' ? files.language : 'html'}
              value={(files as any)[activeTab]}
              onChange={handleEditorChange}
              options={{ fontSize: 13, minimap: { enabled: false }, automaticLayout: true, padding: { top: 12 }, wordWrap: 'on' }}
            />
          </div>
        )}
        {(view === 'preview' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', background: '#000', position: 'relative' }}>
            <iframe ref={iframeRef} title="IDE Preview" style={{ width: '100%', height: '100%', border: 'none' }} sandbox="allow-scripts allow-modals allow-same-origin" />
            {isCompiling && (
              <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'rgba(0,0,0,0.6)', zIndex: 20 }}>
                <RotateCw size={20} className="animate-spin text-blue-500" />
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
});

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { 
  Folder, 
  FolderOpen, 
  FileText, 
  ChevronRight, 
  ChevronDown, 
  Plus, 
  FolderPlus, 
  Trash2, 
  Edit2,
  Check,
  Upload,
  Image as ImageIcon,
  Music,
  Box as BoxIcon
} from 'lucide-react';
import { FileNode, NodeType } from '../types';
import { v4 as uuidv4 } from 'uuid';

interface SidebarProps {
  nodes: FileNode[];
  activeFileId: string | null;
  expandedFolders: Set<string>;
  onFileSelect: (id: string) => void;
  onToggleFolder: (id: string) => void;
  onAddFile: (parentId: string | null) => void;
  onAddFolder: (parentId: string | null) => void;
  onDeleteNode: (id: string) => void;
  onRenameNode: (id: string, newName: string) => void;
  onMoveNode: (nodeId: string, newParentId: string | null) => void;
  onBulkAddNodes?: (nodes: FileNode[]) => void;
}

type NodeMap = Map<string | null, FileNode[]>;

const getFileIcon = (name: string, isFolder: boolean, isExpanded: boolean, isActive: boolean) => {
  if (isFolder) return isExpanded ? <FolderOpen size={16} /> : <Folder size={16} />;

  const ext = name.split('.').pop()?.toLowerCase();
  if (['png', 'jpg', 'jpeg', 'gif', 'svg', 'webp'].includes(ext || '')) return <ImageIcon size={16} />;
  if (['mp3', 'wav', 'ogg'].includes(ext || '')) return <Music size={16} />;
  if (['glb', 'gltf', 'obj'].includes(ext || '')) return <BoxIcon size={16} />;
  return <FileText size={16} />;
};

interface NodeItemProps extends Omit<SidebarProps, 'nodes'> {
  node: FileNode;
  level: number;
  nodeMap: NodeMap;
  editingId: string | null;
  onEditStart: (id: string) => void;
  onEditCancel: () => void;
  onContextMenu: (e: React.MouseEvent, node: FileNode) => void;
}

const NodeItem: React.FC<NodeItemProps> = ({ 
  node, level, nodeMap, activeFileId, expandedFolders, editingId,
  onFileSelect, onToggleFolder, onAddFile, onAddFolder, onDeleteNode, onRenameNode, onMoveNode,
  onEditStart, onEditCancel, onContextMenu
}) => {
  const isEditing = editingId === node.id;
  const [editName, setEditName] = useState(node.name);
  const [isDragOver, setIsDragOver] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const isFolder = node.type === NodeType.FOLDER;
  const isExpanded = expandedFolders.has(node.id);
  const isActive = node.id === activeFileId;
  const children = nodeMap.get(node.id) || [];

  useEffect(() => { if (isEditing) setEditName(node.name); }, [isEditing, node.name]);
  useEffect(() => { if (isEditing && inputRef.current) { inputRef.current.focus(); inputRef.current.select(); } }, [isEditing]);

  const handleRenameSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editName.trim() && editName.trim() !== node.name) onRenameNode(node.id, editName.trim());
    onEditCancel();
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData('nodeId', node.id);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
    if (!isFolder) return;
    const draggedNodeId = e.dataTransfer.getData('nodeId');
    if (draggedNodeId && draggedNodeId !== node.id) onMoveNode(draggedNodeId, node.id);
  };

  return (
    <div style={{ userSelect: 'none' }}>
      <div 
        draggable={!isEditing}
        onDragStart={handleDragStart}
        onDragOver={(e) => { e.preventDefault(); if(isFolder) setIsDragOver(true); }}
        onDragLeave={() => setIsDragOver(false)}
        onDrop={handleDrop}
        className={`sidebar-item ${isActive ? 'active' : ''}`}
        style={{ 
          paddingLeft: `${level * 12 + 8}px`,
          outline: isDragOver ? '2px solid var(--accent-color)' : 'none',
        }}
        onClick={() => isFolder ? onToggleFolder(node.id) : onFileSelect(node.id)}
        onContextMenu={(e) => onContextMenu(e, node)}
      >
        <span style={{ marginRight: '4px', opacity: 0.7, display: 'flex' }}>
          {isFolder && (isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />)}
          {!isFolder && <span style={{ width: '14px' }} />}
        </span>

        <span style={{ marginRight: '8px', color: isActive ? '#fff' : (isFolder ? '#eab308' : 'var(--accent-color)') }}>
          {getFileIcon(node.name, isFolder, isExpanded, isActive)}
        </span>

        {isEditing ? (
          <form onSubmit={handleRenameSubmit} style={{ flex: 1, display: 'flex' }}>
            <input ref={inputRef} value={editName} onChange={e => setEditName(e.target.value)} onBlur={handleRenameSubmit} className="textarea" style={{ height: '20px', padding: '0 4px', fontSize: '12px' }} />
          </form>
        ) : (
          <span style={{ flex: 1, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{node.name}</span>
        )}

        {!isEditing && (
          <div className="sidebar-actions">
             <button onClick={(e) => { e.stopPropagation(); onEditStart(node.id); }} className="btn-icon"><Edit2 size={12} /></button>
             <button onClick={(e) => { e.stopPropagation(); onDeleteNode(node.id); }} className="btn-icon" style={{ color: '#f87171' }}><Trash2 size={12} /></button>
          </div>
        )}
      </div>

      {isFolder && isExpanded && (
        <div>
          {children.map(child => (
            <NodeItem key={child.id} node={child} level={level + 1} nodeMap={nodeMap} editingId={editingId} onEditStart={onEditStart} onEditCancel={onEditCancel} onContextMenu={onContextMenu} {...{activeFileId, expandedFolders, onFileSelect, onToggleFolder, onAddFile, onAddFolder, onDeleteNode, onRenameNode, onMoveNode}} />
          ))}
        </div>
      )}
    </div>
  );
};

export const Sidebar: React.FC<SidebarProps> = (props) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [contextMenu, setContextMenu] = useState<{x: number, y: number, node: FileNode} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const nodeMap = useMemo(() => {
    const map = new Map<string | null, FileNode[]>();
    props.nodes.forEach(node => {
      const parentId = node.parentId;
      if (!map.has(parentId)) map.set(parentId, []);
      map.get(parentId)!.push(node);
    });
    return map;
  }, [props.nodes]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || !props.onBulkAddNodes) return;

    const newNodes: FileNode[] = [];
    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const reader = new FileReader();
      const content = await new Promise<string>((resolve) => {
        reader.onload = () => resolve(reader.result as string);
        // Use readAsDataURL for binary assets, readAsText for md/txt
        const isText = file.name.endsWith('.md') || file.name.endsWith('.txt') || file.name.endsWith('.js') || file.name.endsWith('.css') || file.name.endsWith('.html');
        if (isText) reader.readAsText(file);
        else reader.readAsDataURL(file);
      });

      newNodes.push({
        id: uuidv4(),
        parentId: null,
        name: file.name,
        type: NodeType.FILE,
        content,
        createdAt: Date.now()
      });
    }
    props.onBulkAddNodes(newNodes);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }} onClick={() => setEditingId(null)}>
      <div className="sidebar-header">
        <h2 className="sidebar-title"><FolderOpen size={16} color="var(--accent-color)"/> EXPLORER</h2>
        <div className="flex gap-1">
          <button onClick={() => fileInputRef.current?.click()} className="btn-icon" title="Upload Asset"><Upload size={14} /></button>
          <button onClick={() => props.onAddFile(null)} className="btn-icon" title="New File"><Plus size={14} /></button>
          <button onClick={() => props.onAddFolder(null)} className="btn-icon" title="New Folder"><FolderPlus size={14} /></button>
          <input type="file" ref={fileInputRef} onChange={handleFileUpload} multiple style={{ display: 'none' }} />
        </div>
      </div>
      <div className="sidebar-content no-scrollbar">
        {(nodeMap.get(null) || []).map(node => (
          <NodeItem key={node.id} node={node} level={0} nodeMap={nodeMap} editingId={editingId} onEditStart={setEditingId} onEditCancel={() => setEditingId(null)} onContextMenu={(e, node) => setContextMenu({x: e.clientX, y: e.clientY, node})} {...props} />
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, 
  Upload, 
  FileJson, 
  Settings, 
  X,
  Palette,
  PanelLeft,
  FileText,
  ExternalLink,
  Check,
  Edit3,
  Columns,
  Eye
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, ImportData, AppTheme } from './types';
import { initialNodes } from './initialData';
import * as workspaceClient from './utils/workspaceClient';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(themes.dark);

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
  }, [currentTheme]);

  useEffect(() => { localStorage.setItem('mathsci-fs', JSON.stringify(nodes)); }, [nodes]);

  const activeNode = nodes.find(n => n.id === activeFileId);

  return (
    <div className="app-container">
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '260px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New File.md', type: NodeType.FILE, content: '', createdAt: Date.now() }]);
                setActiveFileId(id);
            }}
            onAddFolder={(parentId) => {
                setNodes(prev => [...prev, { id: uuidv4(), parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
            }}
            onBulkAddNodes={(newNodes) => setNodes(prev => [...prev, ...newNodes])}
            onDeleteNode={(id) => {
                setNodes(prev => prev.filter(n => n.id !== id));
                if (activeFileId === id) setActiveFileId(null);
            }}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon"><PanelLeft size={18} /></button>
                <h1 className="app-title">MathSci</h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={() => setEditorView('editor')} className={`btn ${editorView==='editor'?'active':''}`}><Edit3 size={14}/></button>
                <button onClick={() => setEditorView('split')} className={`btn ${editorView==='split'?'active':''}`}><Columns size={14}/></button>
                <button onClick={() => setEditorView('preview')} className={`btn ${editorView==='preview'?'active':''}`}><Eye size={14}/></button>
            </div>
        </div>
        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeNode ? <Editor content={activeNode.content} fileName={activeNode.name} allNodes={nodes} viewMode={editorView} onChange={(content) => setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n))} /> : null}
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, 
  Eye, FileCode, Hash, Globe, Columns, Square, Save, RotateCw, File, Layers
} from 'lucide-react';
import { FileNode, NodeType } from '../../types';

interface CodeFiles {
  js: string;
  html: string;
  css: string;
  singleHtml?: string;
  mode: 'multi' | 'single';
  language: 'javascript' | 'typescript' | 'html';
}

interface IDEState {
  files: CodeFiles;
  isFullscreen: boolean;
  view: 'split' | 'code' | 'preview';
  activeTab: 'js' | 'html' | 'css' | 'singleHtml';
}

interface CodeEditorEngineProps {
  configStr: string;
  onUpdate?: (newConfig: string) => void;
  blockId: string;
  allFiles?: FileNode[];
}

const ideStateStore: Record<string, IDEState> = {};

export const CodeEditorEngine = React.memo(({ configStr, onUpdate, blockId, allFiles = [] }: CodeEditorEngineProps) => {
  const [state, setState] = useState<IDEState>(() => {
    if (ideStateStore[blockId]) return ideStateStore[blockId];
    try {
      const parsed = JSON.parse(configStr);
      const isSingle = !!parsed.singleHtml || parsed.mode === 'single';
      return {
        files: {
          js: parsed.js || parsed.code || '',
          html: parsed.html || '<div id="app"></div>',
          css: parsed.css || 'body { margin: 0; background: #000; overflow: hidden; }',
          singleHtml: parsed.singleHtml || '<!DOCTYPE html><html><head><script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script></head><body><script>console.log(window.assets);</script></body></html>',
          mode: isSingle ? 'single' : 'multi',
          language: parsed.language || 'javascript'
        },
        isFullscreen: false,
        view: 'split',
        activeTab: isSingle ? 'singleHtml' : 'js'
      };
    } catch (e) {
      return { files: { js: '', html: '', css: '', mode: 'multi', language: 'javascript' }, isFullscreen: false, view: 'split', activeTab: 'js' };
    }
  });

  const { files, isFullscreen, view, activeTab } = state;
  const [isCompiling, setIsCompiling] = useState(false);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => { ideStateStore[blockId] = state; }, [state, blockId]);

  const generateAssetScript = useMemo(() => {
    const assetMap: Record<string, string> = {};
    allFiles.forEach(node => { if (node.type === NodeType.FILE) assetMap[node.name] = node.content; });
    return `window.assets = ${JSON.stringify(assetMap)};`;
  }, [allFiles]);

  const generateSource = useMemo(() => {
    if (files.mode === 'single') return (files.singleHtml || '').replace('<head>', `<head><script>${generateAssetScript}</script>`);
    return `
      <!DOCTYPE html><html><head>
          <script>${generateAssetScript}</script>
          <style>${files.css} body { margin: 0; overflow: hidden; }</style>
          <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
        </head><body>${files.html}<script type="module">${files.js}</script></body></html>
    `;
  }, [files, generateAssetScript]);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);
    if (onUpdate) onUpdate(JSON.stringify(files, null, 2));
    setHasUnsavedChanges(false);
    const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
    if (doc) { doc.open(); doc.write(generateSource); doc.close(); }
    setTimeout(() => setIsCompiling(false), 500);
  }, [generateSource, files, onUpdate]);

  useEffect(() => { const t = setTimeout(runCode, 500); return () => clearTimeout(t); }, []);

  const containerStyle: React.CSSProperties = isFullscreen ? { position: 'fixed', inset: 0, zIndex: 10000, background: '#030712', display: 'flex', flexDirection: 'column' } : { position: 'relative', background: '#111827', borderRadius: '8px', border: '1px solid #1f2937', height: '500px', width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1rem 0' };

  return (
    <div style={containerStyle}>
      <div style={{ height: '40px', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#111827', padding: '0 8px', overflow: 'hidden' }}>
        <div style={{ display: 'flex', height: '100%', overflowX: 'auto', flex: 1, minWidth: 0 }} className="no-scrollbar">
          {files.mode === 'multi' ? ['js', 'html', 'css'].map(tab => (
            <button key={tab} onClick={() => setState(p => ({ ...p, activeTab: tab as any }))} style={{ padding: '0 12px', background: activeTab === tab ? '#030712' : 'transparent', color: activeTab === tab ? '#3b82f6' : '#9ca3af', border: 'none', borderBottom: activeTab === tab ? '2px solid #3b82f6' : 'none', fontSize: '10px', fontWeight: 700, cursor: 'pointer', flexShrink: 0 }}>{tab.toUpperCase()}</button>
          )) : (
            <button style={{ padding: '0 12px', color: '#3b82f6', border: 'none', borderBottom: '2px solid #3b82f6', fontSize: '10px', fontWeight: 700, flexShrink: 0 }}>INDEX.HTML</button>
          )}
        </div>

        <div style={{ display: 'flex', gap: '6px', alignItems: 'center', flexShrink: 0, paddingLeft: '8px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '9px', background: '#1e293b', padding: '4px 6px', borderRadius: '4px', color: '#94a3b8' }}><Layers size={10} /> {allFiles.length} ASSETS</div>
          <button onClick={() => setState(p => ({ ...p, files: { ...p.files, mode: p.files.mode === 'multi' ? 'single' : 'multi' }, activeTab: p.files.mode === 'multi' ? 'singleHtml' : 'js' }))} style={{ fontSize: '9px', padding: '4px 6px', background: 'rgba(59, 130, 246, 0.1)', color: '#3b82f6', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>{files.mode.toUpperCase()}</button>
          <div style={{ display: 'flex', background: 'rgba(0,0,0,0.3)', padding: '2px', borderRadius: '4px' }}>
             <button onClick={() => setState(p => ({ ...p, view: 'split' }))} style={{ padding: '4px', color: view === 'split' ? '#3b82f6' : '#9ca3af', background: 'transparent', border: 'none' }}><Columns size={14}/></button>
          </div>
          <button onClick={runCode} style={{ background: hasUnsavedChanges ? '#3b82f6' : '#10b981', color: 'white', border: 'none', borderRadius: '4px', height: '28px', padding: '0 10px', fontSize: '10px', fontWeight: 600 }}>{hasUnsavedChanges ? 'RUN' : 'REFRESH'}</button>
          <button onClick={() => setState(p => ({ ...p, isFullscreen: !isFullscreen }))} style={{ padding: '4px', background: '#1f2937', borderRadius: '4px', color: 'white', border: 'none' }}>{isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}</button>
        </div>
      </div>
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {(view === 'code' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', background: '#1e1e1e' }}>
            <Editor height="100%" theme="vs-dark" language={activeTab === 'js' ? 'javascript' : 'html'} value={(files as any)[activeTab]} onChange={v => { handleEditorChange(v); setHasUnsavedChanges(true); }} options={{ fontSize: 13, minimap: { enabled: false } }} />
          </div>
        )}
        {(view === 'preview' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', background: '#000' }}>
            <iframe ref={iframeRef} title="IDE Preview" style={{ width: '100%', height: '100%', border: 'none' }} />
          </div>
        )}
      </div>
    </div>
  );
});

