    if (files.mode === 'single') return (files.singleHtml || '').replace('<head>', `<head><script>${generateAssetScript}</script>`);
    return `
      <!DOCTYPE html><html><head>
          <script>${generateAssetScript}</script>
          <style>${files.css} body { margin: 0; overflow: hidden; }</style>
          <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
        </head><body>${files.html}<script type="module">${files.js}</script></body></html>
    `;
  }, [files, generateAssetScript]);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);
    if (onUpdate) onUpdate(JSON.stringify(files, null, 2));
    setHasUnsavedChanges(false);
    const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
    if (doc) { doc.open(); doc.write(generateSource); doc.close(); }
    setTimeout(() => setIsCompiling(false), 500);
  }, [generateSource, files, onUpdate]);

  // Fix: Added handleEditorChange to resolve the missing name error and update local state
  const handleEditorChange = (value: string | undefined) => {
    const content = value || '';
    setState(prev => ({
      ...prev,
      files: {
        ...prev.files,
        [activeTab]: content
      }
    }));
  };

  useEffect(() => { const t = setTimeout(runCode, 500); return () => clearTimeout(t); }, []);

  const containerStyle: React.CSSProperties = isFullscreen ? { position: 'fixed', inset: 0, zIndex: 10000, background: '#030712', display: 'flex', flexDirection: 'column' } : { position: 'relative', background: '#111827', borderRadius: '8px', border: '1px solid #1f2937', height: '500px', width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1rem 0' };

  return (
    <div style={containerStyle}>
      <div style={{ height: '40px', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#111827', padding: '0 8px', overflow: 'hidden' }}>
        <div style={{ display: 'flex', height: '100%', overflowX: 'auto', flex: 1, minWidth: 0 }} className="no-scrollbar">
          {files.mode === 'multi' ? ['js', 'html', 'css'].map(tab => (
            <button key={tab} onClick={() => setState(p => ({ ...p, activeTab: tab as any }))} style={{ padding: '0 12px', background: activeTab === tab ? '#030712' : 'transparent', color: activeTab === tab ? '#3b82f6' : '#9ca3af', border: 'none', borderBottom: activeTab === tab ? '2px solid #3b82f6' : 'none', fontSize: '10px', fontWeight: 700, cursor: 'pointer', flexShrink: 0 }}>{tab.toUpperCase()}</button>
          )) : (
            <button style={{ padding: '0 12px', color: '#3b82f6', border: 'none', borderBottom: '2px solid #3b82f6', fontSize: '10px', fontWeight: 700, flexShrink: 0 }}>INDEX.HTML</button>
          )}
        </div>

        <div style={{ display: 'flex', gap: '6px', alignItems: 'center', flexShrink: 0, paddingLeft: '8px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '9px', background: '#1e293b', padding: '4px 6px', borderRadius: '4px', color: '#94a3b8' }}><Layers size={10} /> {allFiles.length} ASSETS</div>
          <button onClick={() => setState(p => ({ ...p, files: { ...p.files, mode: p.files.mode === 'multi' ? 'single' : 'multi' }, activeTab: p.files.mode === 'multi' ? 'singleHtml' : 'js' }))} style={{ fontSize: '9px', padding: '4px 6px', background: 'rgba(59, 130, 246, 0.1)', color: '#3b82f6', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>{files.mode.toUpperCase()}</button>
          <div style={{ display: 'flex', background: 'rgba(0,0,0,0.3)', padding: '2px', borderRadius: '4px' }}>
             <button onClick={() => setState(p => ({ ...p, view: 'split' }))} style={{ padding: '4px', color: view === 'split' ? '#3b82f6' : '#9ca3af', background: 'transparent', border: 'none' }}><Columns size={14}/></button>
          </div>
          <button onClick={runCode} style={{ background: hasUnsavedChanges ? '#3b82f6' : '#10b981', color: 'white', border: 'none', borderRadius: '4px', height: '28px', padding: '0 10px', fontSize: '10px', fontWeight: 600 }}>{hasUnsavedChanges ? 'RUN' : 'REFRESH'}</button>
          <button onClick={() => setState(p => ({ ...p, isFullscreen: !isFullscreen }))} style={{ padding: '4px', background: '#1f2937', borderRadius: '4px', color: 'white', border: 'none' }}>{isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}</button>
        </div>
      </div>
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {(view === 'code' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', background: '#1e1e1e' }}>
            <Editor height="100%" theme="vs-dark" language={activeTab === 'js' ? 'javascript' : 'html'} value={(files as any)[activeTab]} onChange={v => { handleEditorChange(v); setHasUnsavedChanges(true); }} options={{ fontSize: 13, minimap: { enabled: false } }} />
          </div>
        )}
        {(view === 'preview' || view === 'split') && (
          <div style={{ flex: 1, height: '100%', background: '#000' }}>
            <iframe ref={iframeRef} title="IDE Preview" style={{ width: '100%', height: '100%', border: 'none' }} />
          </div>
        )}
      </div>
    </div>
  );
});

