const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => { localStorage.setItem('mathsci-fs', JSON.stringify(nodes)); }, [nodes]);

  const updateThemeProp = (prop: keyof AppTheme, value: string) => {
    setCurrentTheme(prev => ({ ...prev, name: 'Custom', [prop]: value }));
  };

  return (
    <div className="app-container">
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'Untitled.md', type: NodeType.FILE, content: '', createdAt: Date.now() }]);
                setActiveFileId(id);
            }}
            onAddFolder={(parentId) => {
                setNodes(prev => [...prev, { id: uuidv4(), parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
            }}
            onDeleteNode={(id) => {
                setNodes(prev => prev.filter(n => n.id !== id));
                if (activeFileId === id) setActiveFileId(null);
            }}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon"><PanelLeft size={18} /></button>
                <h1 className="app-title">MathSci</h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={() => setShowSettings(true)} className="btn"><Palette size={14} /> Theme</button>
                <div className="divider"></div>
                <div style={{ display: 'flex', background: 'var(--bg-main)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px', gap: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {nodes.find(n => n.id === activeFileId) ? (
                <Editor 
                  content={nodes.find(n => n.id === activeFileId)!.content} 
                  fileName={nodes.find(n => n.id === activeFileId)!.name}
                  allNodes={nodes}
                  viewMode={editorView}
                  onChange={(content) => setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n))} 
                />
            ) : null}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay">
              <div className="modal" style={{ maxWidth: '420px', background: '#0a0f1d', color: '#f8fafc', border: '1px solid #1e293b', padding: '1.5rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <Palette size={20} color="#3b82f6" />
                        <span style={{ fontSize: '1.125rem', fontWeight: 600 }}>Theme Settings</span>
                      </div>
                      <button onClick={() => setShowSettings(false)} className="btn-icon"><X size={20}/></button>
                  </div>

                  <div style={{ marginBottom: '2rem' }}>
                    <label style={{ fontSize: '0.85rem', color: '#94a3b8', marginBottom: '1rem', display: 'block' }}>Presets</label>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                        {Object.entries(themes).map(([k, t]) => (
                            <button 
                                key={k} onClick={() => setCurrentTheme(t)} 
                                style={{ padding: '0.75rem', borderRadius: '8px', background: t.bgMain, color: t.textMain, border: `1px solid ${currentTheme.name === t.name ? '#3b82f6' : '#1e293b'}`, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.9rem' }}
                            >
                                <div style={{ width: 12, height: 12, borderRadius: '50%', background: t.accent }} />
                                {t.name}
                            </button>
                        ))}
                    </div>
                  </div>

                  <div style={{ marginBottom: '2rem' }}>
                    <label style={{ fontSize: '0.85rem', color: '#94a3b8', marginBottom: '1rem', display: 'block' }}>Custom Colors</label>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                        {[
                          { label: 'Main Background', key: 'bgMain' },
                          { label: 'Sidebar Background', key: 'bgSidebar' },
                          { label: 'Text Color', key: 'textMain' },
                          { label: 'Accent Color', key: 'accent' }
                        ].map(item => (
                          <div key={item.key} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                            <span style={{ fontSize: '0.9rem' }}>{item.label}</span>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                                <span style={{ fontFamily: 'monospace', fontSize: '0.85rem', opacity: 0.5 }}>{(currentTheme as any)[item.key]}</span>
                                <input 
                                  type="color" 
                                  value={(currentTheme as any)[item.key]} 
                                  onChange={(e) => updateThemeProp(item.key as any, e.target.value)}
                                  style={{ width: '32px', height: '32px', border: 'none', background: 'none', cursor: 'pointer' }}
                                />
                            </div>
                          </div>
                        ))}
                    </div>
                  </div>

                  <button 
                    onClick={() => setShowSettings(false)} 
                    style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: '#d97706', color: 'white', border: 'none', fontWeight: 600, cursor: 'pointer' }}
                  >
                    Done
                  </button>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, Eye, FileCode, Hash, Globe, Columns, Square, Save, RotateCw, File, Layers
} from 'lucide-react';
import { FileNode, NodeType } from '../../types';

interface CodeFiles {
  js: string; html: string; css: string; singleHtml?: string; mode: 'multi' | 'single';
}

interface IDEState {
  files: CodeFiles; isFullscreen: boolean; view: 'split' | 'code' | 'preview'; activeTab: 'js' | 'html' | 'css' | 'singleHtml';
}

interface CodeEditorEngineProps {
  configStr: string; onUpdate?: (newConfig: string) => void; blockId: string; allFiles?: FileNode[];
}

const ideStateStore: Record<string, IDEState> = {};

export const CodeEditorEngine = React.memo(({ configStr, onUpdate, blockId, allFiles = [] }: CodeEditorEngineProps) => {
  const [state, setState] = useState<IDEState>(() => {
    if (ideStateStore[blockId]) return ideStateStore[blockId];
    try {
      const parsed = JSON.parse(configStr);
      const isSingle = !!parsed.singleHtml || parsed.mode === 'single';
      return {
        files: {
          js: parsed.js || parsed.code || '',
          html: parsed.html || '<div id="app"></div>',
          css: parsed.css || 'body { margin: 0; background: #000; color: #fff; }',
          singleHtml: parsed.singleHtml || '<!DOCTYPE html><html><head></head><body></body></html>',
          mode: isSingle ? 'single' : 'multi'
        },
        isFullscreen: false, view: 'split', activeTab: isSingle ? 'singleHtml' : 'js'
      };
    } catch (e) {
      return { files: { js: '', html: '', css: '', mode: 'multi' }, isFullscreen: false, view: 'split', activeTab: 'js' };
    }
  });

  const { files, isFullscreen, view, activeTab } = state;
  const [isCompiling, setIsCompiling] = useState(false);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => { ideStateStore[blockId] = state; }, [state, blockId]);

  const handleEditorChange = (value: string | undefined) => {
    const newVal = value || '';
    setState(prev => ({ ...prev, files: { ...prev.files, [activeTab]: newVal } }));
    setHasUnsavedChanges(true);
  };

  const generateAssetScript = useMemo(() => {
    const assetMap: Record<string, string> = {};
    allFiles.forEach(node => { if (node.type === NodeType.FILE) assetMap[node.name] = node.content; });
    return `window.assets = ${JSON.stringify(assetMap)};`;
  }, [allFiles]);

  const generateSource = useMemo(() => {
    if (files.mode === 'single') return (files.singleHtml || '').replace('<head>', `<head><script>${generateAssetScript}</script>`);
    return `
      <!DOCTYPE html><html><head>
          <script>${generateAssetScript}</script>
          <style>${files.css} body { margin: 0; }</style>
        </head><body>${files.html}<script type="module">${files.js}</script></body></html>
    `;
  }, [files, generateAssetScript]);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);
    if (onUpdate) onUpdate(JSON.stringify(files, null, 2));
    setHasUnsavedChanges(false);
    const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
    if (doc) { doc.open(); doc.write(generateSource); doc.close(); }
    setTimeout(() => setIsCompiling(false), 500);
  }, [generateSource, files, onUpdate]);

  useEffect(() => { const t = setTimeout(runCode, 500); return () => clearTimeout(t); }, []);

  const containerStyle: React.CSSProperties = isFullscreen ? { position: 'fixed', inset: 0, zIndex: 10000, background: '#030712', display: 'flex', flexDirection: 'column' } : { position: 'relative', background: '#111827', borderRadius: '8px', border: '1px solid #1f2937', height: '500px', width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1rem 0' };

  return (
    <div style={containerStyle}>
      <div style={{ height: '40px', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#111827', padding: '0 8px' }}>
        <div style={{ display: 'flex', height: '100%', flex: 1, minWidth: 0, overflowX: 'auto' }} className="no-scrollbar">
          {files.mode === 'multi' ? ['js', 'html', 'css'].map(tab => (
            <button key={tab} onClick={() => setState(p => ({ ...p, activeTab: tab as any }))} style={{ padding: '0 12px', background: activeTab === tab ? '#030712' : 'transparent', color: activeTab === tab ? '#3b82f6' : '#9ca3af', border: 'none', borderBottom: activeTab === tab ? '2px solid #3b82f6' : 'none', fontSize: '11px', fontWeight: 700, cursor: 'pointer', flexShrink: 0 }}>{tab.toUpperCase()}</button>
          )) : (
            <button style={{ padding: '0 12px', color: '#3b82f6', border: 'none', borderBottom: '2px solid #3b82f6', fontSize: '11px', fontWeight: 700, flexShrink: 0 }}>INDEX.HTML</button>
          )}
        </div>

        <div style={{ display: 'flex', gap: '6px', alignItems: 'center', flexShrink: 0 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '9px', background: '#1e293b', padding: '4px 6px', borderRadius: '4px', color: '#94a3b8' }}><Layers size={10} /> {allFiles.length} ASSETS</div>
          <button onClick={() => setState(p => ({ ...p, files: { ...p.files, mode: p.files.mode === 'multi' ? 'single' : 'multi' }, activeTab: p.files.mode === 'multi' ? 'singleHtml' : 'js' }))} style={{ fontSize: '9px', padding: '4px 6px', background: '#1e293b', color: '#3b82f6', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>{files.mode.toUpperCase()}</button>
          <button onClick={runCode} style={{ background: hasUnsavedChanges ? '#3b82f6' : '#10b981', color: 'white', border: 'none', borderRadius: '4px', height: '28px', padding: '0 10px', fontSize: '10px', fontWeight: 600 }}>RUN</button>
          <button onClick={() => setState(p => ({ ...p, isFullscreen: !isFullscreen }))} style={{ padding: '4px', background: '#1f2937', borderRadius: '4px', color: 'white', border: 'none' }}>{isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}</button>
        </div>
      </div>
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        <div style={{ flex: view === 'split' ? 1 : (view === 'code' ? 1 : 0), display: view === 'preview' ? 'none' : 'block', height: '100%', background: '#1e1e1e' }}>
          <Editor height="100%" theme="vs-dark" language={activeTab === 'js' ? 'javascript' : 'html'} value={(files as any)[activeTab]} onChange={handleEditorChange} options={{ fontSize: 13, minimap: { enabled: false } }} />
        </div>
        <div style={{ flex: view === 'split' ? 1 : (view === 'preview' ? 1 : 0), display: view === 'code' ? 'none' : 'block', height: '100%', background: '#000' }}>
          <iframe ref={iframeRef} title="IDE Preview" style={{ width: '100%', height: '100%', border: 'none' }} />
        </div>
      </div>
    </div>
  );
});

'use client';
import React, { useRef, useState } from 'react';
import { 
  Bold, Italic, Strikethrough, 
  Heading1, Heading2, Heading3, 
  List, ListOrdered, CheckSquare, 
  Quote, Code, Link, Image, Table, Minus,
  Sigma, Workflow, Hexagon, Activity, Atom, 
  Terminal, Upload, FileImage, Globe, Copy, Check, X,
  Layout
} from 'lucide-react';
import { 
  PLOT_TEMPLATE, PHYSICS_TEMPLATE, REACTION_TEMPLATE, IDE_TEMPLATE 
} from './templates';
import { compressImageToTarget } from '../../utils/imageUtils';

type TabName = 'Write' | 'Insert' | 'Math/Sci';

export const EditorToolbar = ({ insertFormat, readOnly }: { insertFormat: (p: string, s?: string, b?: boolean) => void, readOnly?: boolean }) => {
  const [activeTab, setActiveTab] = useState<TabName>('Write');
  const [uploadStatus, setUploadStatus] = useState<{name: string, syntax: string, size?: number} | null>(null);
  const [copied, setCopied] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (readOnly) return null;

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const compressed = await compressImageToTarget(file, 10 * 1024);
      if (!compressed) {
        alert('Could not compress image. Try a different image.');
        if (fileInputRef.current) fileInputRef.current.value = '';
        return;
      }
      const { dataUrl, size } = compressed;
      const syntax = `<img src="${dataUrl}" alt="${file.name}" />`;
      insertFormat(`\n${syntax}\n`, '', true);
      setUploadStatus({ name: file.name, syntax, size });
    } catch (err) {
      console.error(err);
      alert('Failed to upload image.');
    } finally {
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const copyToClipboard = () => {
    if (uploadStatus) {
      navigator.clipboard.writeText(uploadStatus.syntax);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const ToolbarButton = ({ icon: Icon, title, action, color }: { icon: any, title: string, action: () => void, color?: string }) => (
    <button 
      onClick={action} 
      className="btn-icon" 
      title={title} 
      style={{ color: color, padding: '0.4rem', borderRadius: '4px' }}
    >
      <Icon size={16} />
    </button>
  );

  const Group = ({ children, label }: { children: React.ReactNode, label?: string }) => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '2px', padding: '0 8px', borderRight: '1px solid var(--border-color)', position: 'relative' }}>
      {children}
      {label && <span style={{ position: 'absolute', bottom: '-4px', left: 0, right: 0, textAlign: 'center', fontSize: '6px', color: 'var(--text-muted)', textTransform: 'uppercase', opacity: 0.6 }}>{label}</span>}
    </div>
  );

  return (
    <div className="editor-toolbar" style={{ borderBottom: '1px solid var(--border-color)', background: 'var(--bg-toolbar)', position: 'relative' }}>
       <div className="flex px-4 py-2 gap-2" style={{ background: 'var(--bg-main)' }}>
          {['Write', 'Insert', 'Math/Sci'].map((tab) => (
             <button
               key={tab}
               onClick={() => setActiveTab(tab as TabName)}
               style={{
                 padding: '0.2rem 0.75rem',
                 fontSize: '0.7rem',
                 fontWeight: 600,
                 borderRadius: '20px',
                 border: '1px solid var(--border-color)',
                 background: activeTab === tab ? 'var(--text-main)' : 'transparent',
                 color: activeTab === tab ? 'var(--bg-main)' : 'var(--text-main)',
                 cursor: 'pointer'
               }}
             >
               {tab}
             </button>
          ))}
       </div>

       <div className="px-2 pb-2 flex items-center overflow-x-auto h-12 no-scrollbar">
          {activeTab === 'Write' && (
            <>
              {/* Fix missing children errors by wrapping buttons inside the Group component */}
              <Group label="Text">
                <ToolbarButton icon={Bold} title="Bold" action={() => insertFormat('**', '**')} />
                <ToolbarButton icon={Italic} title="Italic" action={() => insertFormat('*', '*')} />
                <ToolbarButton icon={Strikethrough} title="Strike" action={() => insertFormat('~~', '~~')} />
              </Group>
              <Group label="Header">
                <ToolbarButton icon={Heading1} title="H1" action={() => insertFormat('# ', '', true)} />
                <ToolbarButton icon={Heading2} title="H2" action={() => insertFormat('## ', '', true)} />
              </Group>
              <Group label="List">
                <ToolbarButton icon={List} title="Unordered" action={() => insertFormat('- ', '', true)} />
                <ToolbarButton icon={CheckSquare} title="Tasks" action={() => insertFormat('- [ ] ', '', true)} />
              </Group>
            </>
          )}

          {activeTab === 'Insert' && (
            <>
              {/* Fix missing children errors by wrapping buttons inside the Group component */}
              <Group label="Media">
                <ToolbarButton icon={Link} title="Web Link" action={() => insertFormat('[text](', ')') } />
                <ToolbarButton icon={Globe} title="Image URL" action={() => insertFormat('![alt](', ')') } />
                <ToolbarButton icon={Upload} title="Upload File" action={() => fileInputRef.current?.click()} color="var(--accent-color)" />
                <input type="file" ref={fileInputRef} onChange={handleImageUpload} accept="image/*" style={{ display: 'none' }} />
              </Group>
              <Group label="Code">
                <ToolbarButton icon={Code} title="Inline" action={() => insertFormat('`', '`')} />
                <ToolbarButton icon={Terminal} title="Block" action={() => insertFormat('```\n', '\n```', true)} />
                <ToolbarButton icon={Layout} title="IDE" action={() => insertFormat(IDE_TEMPLATE, '', true)} color="#10b981" />
              </Group>
              <Group label="Diagram">
                <ToolbarButton icon={Workflow} title="Mermaid" action={() => insertFormat('```mermaid\n', '\n```', true)} color="#c084fc" />
                <ToolbarButton icon={Activity} title="Plotly" action={() => insertFormat(PLOT_TEMPLATE, '', true)} color="#c084fc" />
              </Group>
            </>
          )}

          {activeTab === 'Math/Sci' && (
            <>
              {/* Fix missing children errors by wrapping buttons inside the Group component */}
              <Group label="LaTeX">
                <ToolbarButton icon={Sigma} title="Math" action={() => insertFormat('$$\n', '\n$$', true)} color="#60a5fa" />
              </Group>
              <Group label="Chemistry">
                <ToolbarButton icon={Hexagon} title="SMILES" action={() => insertFormat('```smiles\n', '\n```', true)} color="#60a5fa" />
                <ToolbarButton icon={Activity} title="Reaction" action={() => insertFormat(REACTION_TEMPLATE, '', true)} color="#60a5fa" />
              </Group>
              <Group label="Physics">
                <ToolbarButton icon={Atom} title="Physics" action={() => insertFormat(PHYSICS_TEMPLATE, '', true)} color="#f87171" />
              </Group>
            </>
          )}
       </div>

       {uploadStatus && (
         <div style={{ position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 100, background: 'var(--bg-sidebar)', borderBottom: '1px solid var(--border-color)', padding: '0.5rem 1rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between', fontSize: '0.75rem', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', flex: 1, overflow: 'hidden' }}>
                <FileImage size={14} color="var(--accent-color)" />
                <span style={{ color: 'var(--text-muted)' }}>Uploaded:</span>
                <code style={{ background: 'var(--hover-bg)', padding: '2px 4px', borderRadius: '4px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{uploadStatus.syntax}</code>
                {uploadStatus.size !== undefined && <span style={{ marginLeft: '0.5rem', color: 'var(--text-muted)', fontFamily: 'monospace' }}>({(uploadStatus.size / 1024).toFixed(1)} KB)</span>}
            </div>
            <div style={{ display: 'flex', gap: '0.5rem', marginLeft: '1rem' }}>
                <button onClick={copyToClipboard} className="btn" style={{ padding: '0.2rem 0.5rem' }}>
                    {copied ? <Check size={12} color="#4ade80" /> : <Copy size={12} />}
                    {copied ? 'Copied' : 'Copy'}
                </button>
                <button onClick={() => setUploadStatus(null)} className="btn-icon" style={{ padding: '2px' }}><X size={14}/></button>
            </div>
         </div>
       )}
    </div>
  );
};

import React, { useState, useRef, useMemo, useCallback } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const previewRef = useRef<HTMLDivElement>(null);
  const isSyncingScroll = useRef(false);

  const handleEditorScroll = () => {
    if (isSyncingScroll.current || viewMode !== 'split' || !textareaRef.current || !previewRef.current) return;
    isSyncingScroll.current = true;
    const { scrollTop, scrollHeight, clientHeight } = textareaRef.current;
    const scrollPercent = scrollTop / (scrollHeight - clientHeight);
    const preview = previewRef.current;
    preview.scrollTop = scrollPercent * (preview.scrollHeight - preview.clientHeight);
    setTimeout(() => { isSyncingScroll.current = false; }, 50);
  };

  const handlePreviewScroll = () => {
    if (isSyncingScroll.current || viewMode !== 'split' || !textareaRef.current || !previewRef.current) return;
    isSyncingScroll.current = true;
    const { scrollTop, scrollHeight, clientHeight } = previewRef.current;
    const scrollPercent = scrollTop / (scrollHeight - clientHeight);
    const textarea = textareaRef.current;
    textarea.scrollTop = scrollPercent * (textarea.scrollHeight - textarea.clientHeight);
    setTimeout(() => { isSyncingScroll.current = false; }, 50);
  };

  const handleIDEUpdate = useCallback((oldConfig: string, newConfig: string) => {
    if (oldConfig === newConfig) return;

    // Exact match replacement for the specific code block
    const fullOldBlock = '```ide\n' + oldConfig + '\n```';
    const fullNewBlock = '```ide\n' + newConfig + '\n```';

    if (content.includes(fullOldBlock)) {
      const updatedContent = content.replace(fullOldBlock, fullNewBlock);
      onChange(updatedContent);
    }
  }, [content, onChange]);

  const markdownComponents = useMemo(() => ({
    a: ({node, ...props}: any) => <a {...props} target="_blank" rel="noopener noreferrer" />,
    img: ({ src, alt }: any) => {
      if (!src) return null;
      return <img src={src} alt={alt || ''} style={{ maxWidth: '100%' }} loading="lazy" />;
    },
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        const codeContent = String(children).replace(/\n$/, '');
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={codeContent} />;
            case 'smiles': return <SmilesDiagram smiles={codeContent} />;
            case 'plot': return <InteractivePlot configStr={codeContent} />;
            case 'physics': return <PhysicsSimulation configStr={codeContent} />;
            case 'ide': {
              // Create a unique ID for each block based on file and a hash of content
              // We use a simple hash to differentiate between multiple identical templates
              let hash = 0;
              for (let i = 0; i < codeContent.length; i++) {
                hash = ((hash << 5) - hash) + codeContent.charCodeAt(i);
                hash |= 0;
              }
              const blockId = `ide-${fileName}-${hash}`;

              return (
                <CodeEditorEngine 
                  key={blockId}
                  blockId={blockId}
                  configStr={codeContent} 
                  allFiles={allNodes}
                  onUpdate={(newVal) => handleIDEUpdate(codeContent, newVal)}
                />
              );
            }
          }
        }
        return <code className={className} {...props}>{children}</code>;
    },
    'model-viewer': ({node, ...props}: any) => React.createElement('model-viewer', props),
    div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
    span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
  }), [handleIDEUpdate, fileName, allNodes]);

  const insertFormat = (prefix: string, suffix: string = '', blockMode: boolean = false) => {
    if (!textareaRef.current || readOnly) return;
    const { selectionStart: start, selectionEnd: end, value: text } = textareaRef.current;
    const selected = text.substring(start, end);
    let newText = '', newCursor = 0;
    if (blockMode) {
        const hasNewline = text.substring(0, start).endsWith('\n') || start === 0;
        newText = `${text.substring(0, start)}${hasNewline ? '' : '\n'}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + (hasNewline ? 0 : 1) + selected.length;
    } else {
        newText = `${text.substring(0, start)}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + selected.length;
    }
    onChange(newText);
    setTimeout(() => { textareaRef.current?.focus(); textareaRef.current?.setSelectionRange(newCursor, newCursor); }, 0);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const { selectionStart: start, selectionEnd: end, value } = e.currentTarget;
      onChange(value.substring(0, start) + '  ' + value.substring(end));
      setTimeout(() => { if(textareaRef.current) textareaRef.current.selectionStart = textareaRef.current.selectionEnd = start + 2; }, 0);
    }
  };

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>

      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={content} 
                  onChange={e => onChange(e.target.value)} 
                  onKeyDown={handleKeyDown}
                  onScroll={handleEditorScroll}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div 
              ref={previewRef}
              onScroll={handlePreviewScroll}
              id="markdown-preview" 
              className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}
            >
                <div className="markdown-body">
                    <ReactMarkdown 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents}
                        urlTransform={(url) => url}
                        remarkRehypeOptions={{ 
                          handlers: { 
                            math: (s:any, n:any) => ({ type: 'element', tagName: 'div', properties: { className: ['math-display'], 'data-math': n.value }, children: [] }), 
                            inlineMath: (s:any, n:any) => ({ type: 'element', tagName: 'span', properties: { className: ['math-inline'], 'data-math': n.value }, children: [] }) 
                          } 
                        }}
                    >
                      {content}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, Layers
} from 'lucide-react';
import { FileNode, NodeType } from '../../types';

interface CodeFiles {
  js: string; html: string; css: string; singleHtml?: string; mode: 'multi' | 'single';
}

interface IDEState {
  files: CodeFiles; isFullscreen: boolean; view: 'split' | 'code' | 'preview'; activeTab: 'js' | 'html' | 'css' | 'singleHtml';
}

interface CodeEditorEngineProps {
  configStr: string; onUpdate?: (newConfig: string) => void; blockId: string; allFiles?: FileNode[];
}

// Memory store to keep IDE state alive across re-renders within the same session
const ideStateStore: Record<string, IDEState> = {};

export const CodeEditorEngine = React.memo(({ configStr, onUpdate, blockId, allFiles = [] }: CodeEditorEngineProps) => {
  const [state, setState] = useState<IDEState>(() => {
    // Check global store first
    if (ideStateStore[blockId]) return ideStateStore[blockId];

    // Fallback to initial config
    try {
      const parsed = JSON.parse(configStr);
      const isSingle = !!parsed.singleHtml || parsed.mode === 'single';
      const initialState: IDEState = {
        files: {
          js: parsed.js || parsed.code || '',
          html: parsed.html || '<div id="app"></div>',
          css: parsed.css || 'body { margin: 0; background: #000; color: #fff; }',
          singleHtml: parsed.singleHtml || '<!DOCTYPE html><html><head></head><body></body></html>',
          mode: isSingle ? 'single' : 'multi'
        },
        isFullscreen: false, 
        view: 'split', 
        activeTab: isSingle ? 'singleHtml' : 'js'
      };

      // Save initial state to store immediately to anchor this blockId
      ideStateStore[blockId] = initialState;
      return initialState;
    } catch (e) {
      const fallback: IDEState = { 
        files: { js: '', html: '', css: '', mode: 'multi' }, 
        isFullscreen: false, 
        view: 'split', 
        activeTab: 'js' 
      };
      ideStateStore[blockId] = fallback;
      return fallback;
    }
  });

  const { files, isFullscreen, view, activeTab } = state;
  const [isCompiling, setIsCompiling] = useState(false);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  // Sync state to store whenever it changes
  useEffect(() => { 
    ideStateStore[blockId] = state; 
  }, [state, blockId]);

  const handleEditorChange = (value: string | undefined) => {
    const newVal = value || '';
    setState(prev => ({ 
      ...prev, 
      files: { ...prev.files, [activeTab]: newVal } 
    }));
    setHasUnsavedChanges(true);
  };

  const generateAssetScript = useMemo(() => {
    const assetMap: Record<string, string> = {};
    allFiles.forEach(node => { 
      if (node.type === NodeType.FILE) assetMap[node.name] = node.content; 
    });
    return `window.assets = ${JSON.stringify(assetMap)};`;
  }, [allFiles]);

  const generateSource = useMemo(() => {
    if (files.mode === 'single') return (files.singleHtml || '').replace('<head>', `<head><script>${generateAssetScript}</script>`);
    return `
      <!DOCTYPE html><html><head>
          <script>${generateAssetScript}</script>
          <style>${files.css} body { margin: 0; overflow: hidden; }</style>
        </head><body>${files.html}<script type="module">${files.js}</script></body></html>
    `;
  }, [files, generateAssetScript]);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);

    // Notify parent about state change so it can save to markdown
    if (onUpdate) onUpdate(JSON.stringify(files, null, 2));

    setHasUnsavedChanges(false);
    const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
    if (doc) { 
      doc.open(); 
      doc.write(generateSource); 
      doc.close(); 
    }
    setTimeout(() => setIsCompiling(false), 300);
  }, [generateSource, files, onUpdate]);

  // Initial run on mount
  useEffect(() => { 
    const t = setTimeout(runCode, 100); 
    return () => clearTimeout(t); 
  }, []);

  const containerStyle: React.CSSProperties = isFullscreen ? { 
    position: 'fixed', inset: 0, zIndex: 10000, background: '#030712', display: 'flex', flexDirection: 'column' 
  } : { 
    position: 'relative', background: '#111827', borderRadius: '8px', border: '1px solid #1f2937', height: '500px', width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1rem 0' 
  };

  return (
    <div style={containerStyle}>
      <div style={{ height: '40px', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#111827', padding: '0 8px' }}>
        <div style={{ display: 'flex', height: '100%', flex: 1, minWidth: 0, overflowX: 'auto' }} className="no-scrollbar">
          {files.mode === 'multi' ? ['js', 'html', 'css'].map(tab => (
            <button key={tab} onClick={() => setState(p => ({ ...p, activeTab: tab as any }))} style={{ padding: '0 12px', background: activeTab === tab ? '#030712' : 'transparent', color: activeTab === tab ? '#3b82f6' : '#9ca3af', border: 'none', borderBottom: activeTab === tab ? '2px solid #3b82f6' : 'none', fontSize: '11px', fontWeight: 700, cursor: 'pointer', flexShrink: 0 }}>{tab.toUpperCase()}</button>
          )) : (
            <button style={{ padding: '0 12px', color: '#3b82f6', border: 'none', borderBottom: '2px solid #3b82f6', fontSize: '11px', fontWeight: 700, flexShrink: 0 }}>INDEX.HTML</button>
          )}
        </div>

        <div style={{ display: 'flex', gap: '8px', alignItems: 'center', flexShrink: 0 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '9px', background: '#1e293b', padding: '4px 8px', borderRadius: '4px', color: '#94a3b8' }}>
            <Layers size={10} /> {allFiles.length} ASSETS
          </div>
          <button 
            onClick={() => setState(p => ({ ...p, files: { ...p.files, mode: p.files.mode === 'multi' ? 'single' : 'multi' }, activeTab: p.files.mode === 'multi' ? 'singleHtml' : 'js' }))} 
            style={{ fontSize: '9px', padding: '4px 8px', background: '#1e293b', color: '#3b82f6', border: 'none', borderRadius: '4px', cursor: 'pointer', fontWeight: 600 }}
          >
            {files.mode.toUpperCase()}
          </button>
          <button 
            onClick={runCode} 
            disabled={isCompiling}
            style={{ background: hasUnsavedChanges ? '#3b82f6' : '#10b981', color: 'white', border: 'none', borderRadius: '4px', height: '28px', padding: '0 12px', fontSize: '10px', fontWeight: 700, cursor: 'pointer' }}
          >
            {isCompiling ? '...' : 'RUN'}
          </button>
          <button 
            onClick={() => setState(p => ({ ...p, isFullscreen: !isFullscreen }))} 
            className="btn-icon"
            style={{ padding: '4px', background: '#1f2937', borderRadius: '4px', color: 'white' }}
          >
            {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
          </button>
        </div>
      </div>
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        <div style={{ flex: view === 'split' ? 1 : (view === 'code' ? 1 : 0), display: view === 'preview' ? 'none' : 'block', height: '100%', background: '#1e1e1e' }}>
          <Editor 
            height="100%" 
            theme="vs-dark" 
            language={activeTab === 'js' ? 'javascript' : (activeTab === 'css' ? 'css' : 'html')} 
            value={(files as any)[activeTab]} 
            onChange={handleEditorChange} 
            options={{ fontSize: 13, minimap: { enabled: false }, scrollBeyondLastLine: false, padding: { top: 10 } }} 
          />
        </div>
        <div style={{ flex: view === 'split' ? 1 : (view === 'preview' ? 1 : 0), display: view === 'code' ? 'none' : 'block', height: '100%', background: '#000' }}>
          <iframe ref={iframeRef} title="IDE Preview" style={{ width: '100%', height: '100%', border: 'none' }} />
        </div>
      </div>
    </div>
  );
});

import React, { useState, useRef, useMemo, useCallback } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const previewRef = useRef<HTMLDivElement>(null);
  const isSyncingScroll = useRef(false);

  // Use a ref to track block counts during a single render pass
  const blockCounter = useRef(0);

  const handleEditorScroll = () => {
    if (isSyncingScroll.current || viewMode !== 'split' || !textareaRef.current || !previewRef.current) return;
    isSyncingScroll.current = true;
    const { scrollTop, scrollHeight, clientHeight } = textareaRef.current;
    const scrollPercent = scrollTop / (scrollHeight - clientHeight);
    const preview = previewRef.current;
    preview.scrollTop = scrollPercent * (preview.scrollHeight - preview.clientHeight);
    setTimeout(() => { isSyncingScroll.current = false; }, 50);
  };

  const handlePreviewScroll = () => {
    if (isSyncingScroll.current || viewMode !== 'split' || !textareaRef.current || !previewRef.current) return;
    isSyncingScroll.current = true;
    const { scrollTop, scrollHeight, clientHeight } = previewRef.current;
    const scrollPercent = scrollTop / (scrollHeight - clientHeight);
    const textarea = textareaRef.current;
    textarea.scrollTop = scrollPercent * (textarea.scrollHeight - textarea.clientHeight);
    setTimeout(() => { isSyncingScroll.current = false; }, 50);
  };

  const handleIDEUpdate = useCallback((oldConfig: string, newConfig: string) => {
    if (oldConfig === newConfig) return;

    // We need to find the specific occurrence. This is tricky with multiple identical blocks.
    // For now, we'll replace the first match which is usually the one being edited.
    const fullOldBlock = '```ide\n' + oldConfig + '\n```';
    const fullNewBlock = '```ide\n' + newConfig + '\n```';

    if (content.includes(fullOldBlock)) {
      const updatedContent = content.replace(fullOldBlock, fullNewBlock);
      onChange(updatedContent);
    }
  }, [content, onChange]);

  const markdownComponents = useMemo(() => {
    // Reset counter on every render cycle
    blockCounter.current = 0;

    return {
      a: ({node, ...props}: any) => <a {...props} target="_blank" rel="noopener noreferrer" />,
      img: ({ src, alt }: any) => {
        if (!src) return null;
        return <img src={src} alt={alt || ''} style={{ maxWidth: '100%' }} loading="lazy" />;
      },
      code({node, inline, className, children, ...props}: any) {
          const match = /language-([\w-]+)/.exec(className || '');
          const codeContent = String(children).replace(/\n$/, '');
          if (!inline) {
            switch (match?.[1]) {
              case 'mermaid': return <MermaidDiagram chart={codeContent} />;
              case 'smiles': return <SmilesDiagram smiles={codeContent} />;
              case 'plot': return <InteractivePlot configStr={codeContent} />;
              case 'physics': return <PhysicsSimulation configStr={codeContent} />;
              case 'ide': {
                const index = blockCounter.current++;
                const blockId = `ide-${fileName}-${index}`;

                return (
                  <CodeEditorEngine 
                    key={blockId}
                    blockId={blockId}
                    configStr={codeContent} 
                    allFiles={allNodes}
                    onUpdate={(newVal) => handleIDEUpdate(codeContent, newVal)}
                  />
                );
              }
            }
          }
          return <code className={className} {...props}>{children}</code>;
      },
      'model-viewer': ({node, ...props}: any) => React.createElement('model-viewer', props),
      div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
      span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
    };
  }, [handleIDEUpdate, fileName, allNodes]);

  const insertFormat = (prefix: string, suffix: string = '', blockMode: boolean = false) => {
    if (!textareaRef.current || readOnly) return;
    const { selectionStart: start, selectionEnd: end, value: text } = textareaRef.current;
    const selected = text.substring(start, end);
    let newText = '', newCursor = 0;
    if (blockMode) {
        const hasNewline = text.substring(0, start).endsWith('\n') || start === 0;
        newText = `${text.substring(0, start)}${hasNewline ? '' : '\n'}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + (hasNewline ? 0 : 1) + selected.length;
    } else {
        newText = `${text.substring(0, start)}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + selected.length;
    }
    onChange(newText);
    setTimeout(() => { textareaRef.current?.focus(); textareaRef.current?.setSelectionRange(newCursor, newCursor); }, 0);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const { selectionStart: start, selectionEnd: end, value } = e.currentTarget;
      onChange(value.substring(0, start) + '  ' + value.substring(end));
      setTimeout(() => { if(textareaRef.current) textareaRef.current.selectionStart = textareaRef.current.selectionEnd = start + 2; }, 0);
    }
  };

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>

      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={content} 
                  onChange={e => onChange(e.target.value)} 
                  onKeyDown={handleKeyDown}
                  onScroll={handleEditorScroll}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div 
              ref={previewRef}
              onScroll={handlePreviewScroll}
              id="markdown-preview" 
              className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}
            >
                <div className="markdown-body">
                    <ReactMarkdown 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents}
                        urlTransform={(url) => url}
                        remarkRehypeOptions={{ 
                          handlers: { 
                            math: (s:any, n:any) => ({ type: 'element', tagName: 'div', properties: { className: ['math-display'], 'data-math': n.value }, children: [] }), 
                            inlineMath: (s:any, n:any) => ({ type: 'element', tagName: 'span', properties: { className: ['math-inline'], 'data-math': n.value }, children: [] }) 
                          } 
                        }}
                    >
                      {content}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, Layers, Edit3, Columns, Eye
} from 'lucide-react';
import { FileNode, NodeType } from '../../types';

interface CodeFiles {
  js: string; html: string; css: string; singleHtml?: string; mode: 'multi' | 'single';
}

interface IDEState {
  files: CodeFiles; 
  isFullscreen: boolean; 
  view: 'split' | 'code' | 'preview'; 
  activeTab: 'js' | 'html' | 'css' | 'singleHtml';
}

interface CodeEditorEngineProps {
  configStr: string; onUpdate?: (newConfig: string) => void; blockId: string; allFiles?: FileNode[];
}

const ideStateStore: Record<string, IDEState> = {};

export const CodeEditorEngine = React.memo(({ configStr, onUpdate, blockId, allFiles = [] }: CodeEditorEngineProps) => {
  const [state, setState] = useState<IDEState>(() => {
    if (ideStateStore[blockId]) return ideStateStore[blockId];

    try {
      const parsed = JSON.parse(configStr);
      const isSingle = !!parsed.singleHtml || parsed.mode === 'single';
      const initialState: IDEState = {
        files: {
          js: parsed.js || parsed.code || '',
          html: parsed.html || '<div id="app"></div>',
          css: parsed.css || 'body { margin: 0; background: #000; color: #fff; }',
          singleHtml: parsed.singleHtml || '<!DOCTYPE html><html><head></head><body></body></html>',
          mode: isSingle ? 'single' : 'multi'
        },
        isFullscreen: false, 
        view: 'split', 
        activeTab: isSingle ? 'singleHtml' : 'js'
      };
      ideStateStore[blockId] = initialState;
      return initialState;
    } catch (e) {
      const fallback: IDEState = { 
        files: { js: '', html: '', css: '', mode: 'multi' }, 
        isFullscreen: false, 
        view: 'split', 
        activeTab: 'js' 
      };
      ideStateStore[blockId] = fallback;
      return fallback;
    }
  });

  const { files, isFullscreen, view, activeTab } = state;
  const [isCompiling, setIsCompiling] = useState(false);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => { 
    ideStateStore[blockId] = state; 
  }, [state, blockId]);

  const handleEditorChange = (value: string | undefined) => {
    const newVal = value || '';
    setState(prev => ({ 
      ...prev, 
      files: { ...prev.files, [activeTab]: newVal } 
    }));
    setHasUnsavedChanges(true);
  };

  const generateAssetScript = useMemo(() => {
    const assetMap: Record<string, string> = {};
    allFiles.forEach(node => { 
      if (node.type === NodeType.FILE) assetMap[node.name] = node.content; 
    });
    return `window.assets = ${JSON.stringify(assetMap)};`;
  }, [allFiles]);

  const generateSource = useMemo(() => {
    if (files.mode === 'single') return (files.singleHtml || '').replace('<head>', `<head><script>${generateAssetScript}</script>`);
    return `
      <!DOCTYPE html><html><head>
          <script>${generateAssetScript}</script>
          <style>${files.css} body { margin: 0; overflow: hidden; height: 100vh; }</style>
        </head><body>${files.html}<script type="module">${files.js}</script></body></html>
    `;
  }, [files, generateAssetScript]);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);
    if (onUpdate) onUpdate(JSON.stringify(files, null, 2));
    setHasUnsavedChanges(false);
    const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
    if (doc) { 
      doc.open(); 
      doc.write(generateSource); 
      doc.close(); 
    }
    setTimeout(() => setIsCompiling(false), 300);
  }, [generateSource, files, onUpdate]);

  useEffect(() => { 
    const t = setTimeout(runCode, 100); 
    return () => clearTimeout(t); 
  }, []);

  const containerStyle: React.CSSProperties = isFullscreen ? { 
    position: 'fixed', inset: 0, zIndex: 10000, background: '#030712', display: 'flex', flexDirection: 'column' 
  } : { 
    position: 'relative', background: '#111827', borderRadius: '8px', border: '1px solid #1f2937', height: '500px', width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1rem 0' 
  };

  return (
    <div style={containerStyle}>
      <div style={{ height: '40px', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#111827', padding: '0 8px' }}>
        <div style={{ display: 'flex', height: '100%', flex: 1, minWidth: 0, overflowX: 'auto' }} className="no-scrollbar">
          {files.mode === 'multi' ? ['js', 'html', 'css'].map(tab => (
            <button key={tab} onClick={() => setState(p => ({ ...p, activeTab: tab as any }))} style={{ padding: '0 12px', background: activeTab === tab ? '#030712' : 'transparent', color: activeTab === tab ? '#3b82f6' : '#9ca3af', border: 'none', borderBottom: activeTab === tab ? '2px solid #3b82f6' : 'none', fontSize: '11px', fontWeight: 700, cursor: 'pointer', flexShrink: 0 }}>{tab.toUpperCase()}</button>
          )) : (
            <button style={{ padding: '0 12px', color: '#3b82f6', border: 'none', borderBottom: '2px solid #3b82f6', fontSize: '11px', fontWeight: 700, flexShrink: 0 }}>INDEX.HTML</button>
          )}
        </div>

        <div style={{ display: 'flex', gap: '8px', alignItems: 'center', flexShrink: 0 }}>
          {/* View Toggle Controls */}
          <div style={{ display: 'flex', background: '#030712', border: '1px solid #1f2937', borderRadius: '6px', padding: '2px', gap: '2px' }}>
             <button onClick={() => setState(p => ({ ...p, view: 'code' }))} className="btn-icon" style={{ padding: '4px', color: view === 'code' ? '#3b82f6' : '#64748b' }}><Edit3 size={14} /></button>
             <button onClick={() => setState(p => ({ ...p, view: 'split' }))} className="btn-icon" style={{ padding: '4px', color: view === 'split' ? '#3b82f6' : '#64748b' }}><Columns size={14} /></button>
             <button onClick={() => setState(p => ({ ...p, view: 'preview' }))} className="btn-icon" style={{ padding: '4px', color: view === 'preview' ? '#3b82f6' : '#64748b' }}><Eye size={14} /></button>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '9px', background: '#1e293b', padding: '4px 8px', borderRadius: '4px', color: '#94a3b8' }}>
            <Layers size={10} /> {allFiles.length} ASSETS
          </div>

          <button 
            onClick={() => setState(p => ({ ...p, files: { ...p.files, mode: p.files.mode === 'multi' ? 'single' : 'multi' }, activeTab: p.files.mode === 'multi' ? 'singleHtml' : 'js' }))} 
            style={{ fontSize: '9px', padding: '4px 8px', background: '#1e293b', color: '#3b82f6', border: 'none', borderRadius: '4px', cursor: 'pointer', fontWeight: 600 }}
          >
            {files.mode.toUpperCase()}
          </button>

          <button 
            onClick={runCode} 
            disabled={isCompiling}
            style={{ background: hasUnsavedChanges ? '#3b82f6' : '#10b981', color: 'white', border: 'none', borderRadius: '4px', height: '28px', padding: '0 12px', fontSize: '10px', fontWeight: 700, cursor: 'pointer' }}
          >
            {isCompiling ? '...' : 'RUN'}
          </button>

          <button 
            onClick={() => setState(p => ({ ...p, isFullscreen: !isFullscreen }))} 
            className="btn-icon"
            style={{ padding: '4px', background: '#1f2937', borderRadius: '4px', color: 'white' }}
          >
            {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
          </button>
        </div>
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        <div style={{ flex: view === 'split' ? 1 : (view === 'code' ? 1 : 0), display: view === 'preview' ? 'none' : 'block', height: '100%', background: '#1e1e1e', borderRight: view === 'split' ? '1px solid #1f2937' : 'none' }}>
          <Editor 
            height="100%" 
            theme="vs-dark" 
            language={activeTab === 'js' ? 'javascript' : (activeTab === 'css' ? 'css' : 'html')} 
            value={(files as any)[activeTab]} 
            onChange={handleEditorChange} 
            options={{ fontSize: 13, minimap: { enabled: false }, scrollBeyondLastLine: false, padding: { top: 10 } }} 
          />
        </div>
        <div style={{ flex: view === 'split' ? 1 : (view === 'preview' ? 1 : 0), display: view === 'code' ? 'none' : 'block', height: '100%', background: '#000' }}>
          <iframe ref={iframeRef} title="IDE Preview" style={{ width: '100%', height: '100%', border: 'none', background: '#fff' }} />
        </div>
      </div>
    </div>
  );
});

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, Layers, Edit3, Columns, Eye
} from 'lucide-react';
import { FileNode, NodeType } from '../../types';

interface CodeFiles {
  js: string; 
  html: string; 
  css: string; 
  singleHtml?: string; 
  mode: 'multi' | 'single';
}

interface IDEState {
  files: CodeFiles; 
  isFullscreen: boolean; 
  view: 'split' | 'code' | 'preview'; 
  activeTab: 'js' | 'html' | 'css' | 'singleHtml';
}

interface CodeEditorEngineProps {
  configStr: string; 
  onUpdate?: (newConfig: string) => void; 
  blockId: string; 
  allFiles?: FileNode[];
}

// Global cache for IDE states to preserve content across tab switches
const ideStateStore: Record<string, IDEState> = {};

export const CodeEditorEngine = React.memo(({ configStr, onUpdate, blockId, allFiles = [] }: CodeEditorEngineProps) => {
  // Initialize state from cache or from the raw config string
  const [state, setState] = useState<IDEState>(() => {
    if (ideStateStore[blockId]) return ideStateStore[blockId];

    try {
      const parsed = JSON.parse(configStr);
      const isSingle = !!parsed.singleHtml || parsed.mode === 'single';
      const initialState: IDEState = {
        files: {
          js: parsed.js || parsed.code || '',
          html: parsed.html || '<div id="app"></div>',
          css: parsed.css || 'body { margin: 0; background: #000; color: #fff; }',
          singleHtml: parsed.singleHtml || '<!DOCTYPE html><html><head></head><body></body></html>',
          mode: isSingle ? 'single' : 'multi'
        },
        isFullscreen: false, 
        view: 'split', 
        activeTab: isSingle ? 'singleHtml' : 'js'
      };
      ideStateStore[blockId] = initialState;
      return initialState;
    } catch (e) {
      return { 
        files: { js: '', html: '', css: '', mode: 'multi' }, 
        isFullscreen: false, 
        view: 'split', 
        activeTab: 'js' 
      };
    }
  });

  const { files, isFullscreen, view, activeTab } = state;
  const [isCompiling, setIsCompiling] = useState(false);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
  const [runIteration, setRunIteration] = useState(0); // Used to force iframe refresh
  const iframeRef = useRef<HTMLIFrameElement>(null);

  // Keep global store in sync
  useEffect(() => { 
    ideStateStore[blockId] = state; 
  }, [state, blockId]);

  const handleEditorChange = (value: string | undefined) => {
    const newVal = value || '';
    setState(prev => ({ 
      ...prev, 
      files: { ...prev.files, [activeTab]: newVal } 
    }));
    setHasUnsavedChanges(true);
  };

  const generateAssetScript = useMemo(() => {
    const assetMap: Record<string, string> = {};
    allFiles.forEach(node => { 
      if (node.type === NodeType.FILE) assetMap[node.name] = node.content; 
    });
    return `window.assets = ${JSON.stringify(assetMap)};`;
  }, [allFiles]);

  const generateSource = useMemo(() => {
    if (files.mode === 'single') {
      return (files.singleHtml || '').replace('<head>', `<head><script>${generateAssetScript}</script>`);
    }
    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="utf-8">
          <script>${generateAssetScript}</script>
          <style>
            ${files.css} 
            body { margin: 0; min-height: 100vh; background-color: white; color: black; }
          </style>
        </head>
        <body>
          ${files.html}
          <script type="module">
            try {
              ${files.js}
            } catch (err) {
              console.error("Runtime Error:", err);
              document.body.innerHTML += '<div style="color:red; font-family:monospace; padding:10px; background:#ffeeee; border:1px solid red; position:fixed; bottom:0; left:0; right:0;">' + err.message + '</div>';
            }
          </script>
        </body>
      </html>
    `;
  }, [files, generateAssetScript]);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);

    // Increment iteration to ensure we are targeting the newest instance if re-mounted
    setRunIteration(prev => prev + 1);

    // Save back to markdown
    if (onUpdate) onUpdate(JSON.stringify(files, null, 2));
    setHasUnsavedChanges(false);

    const target = iframeRef.current;
    const doc = target.contentDocument || target.contentWindow?.document;
    if (doc) { 
      doc.open(); 
      doc.write(generateSource); 
      doc.close(); 
    }

    setTimeout(() => setIsCompiling(false), 400);
  }, [generateSource, files, onUpdate]);

  // Initial compile on mount
  useEffect(() => { 
    const t = setTimeout(runCode, 150); 
    return () => clearTimeout(t); 
  }, []);

  const containerStyle: React.CSSProperties = isFullscreen ? { 
    position: 'fixed', inset: 0, zIndex: 10000, background: '#030712', display: 'flex', flexDirection: 'column' 
  } : { 
    position: 'relative', background: '#111827', borderRadius: '8px', border: '1px solid #1f2937', height: '520px', width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1.5rem 0' 
  };

  return (
    <div style={containerStyle} id={blockId}>
      {/* Toolbar */}
      <div style={{ height: '44px', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#111827', padding: '0 10px' }}>
        <div style={{ display: 'flex', height: '100%', flex: 1, minWidth: 0, overflowX: 'auto' }} className="no-scrollbar">
          {files.mode === 'multi' ? (['js', 'html', 'css'] as const).map(tab => (
            <button 
              key={tab} 
              onClick={() => setState(p => ({ ...p, activeTab: tab }))} 
              style={{ 
                padding: '0 14px', 
                background: activeTab === tab ? '#030712' : 'transparent', 
                color: activeTab === tab ? '#3b82f6' : '#64748b', 
                border: 'none', 
                borderBottom: activeTab === tab ? '2px solid #3b82f6' : 'none', 
                fontSize: '11px', 
                fontWeight: 700, 
                cursor: 'pointer', 
                flexShrink: 0,
                transition: 'all 0.2s'
              }}
            >
              {tab.toUpperCase()}
            </button>
          )) : (
            <button style={{ padding: '0 14px', color: '#3b82f6', border: 'none', borderBottom: '2px solid #3b82f6', fontSize: '11px', fontWeight: 700, flexShrink: 0 }}>INDEX.HTML</button>
          )}
        </div>

        <div style={{ display: 'flex', gap: '10px', alignItems: 'center', flexShrink: 0 }}>
          {/* View Toggles */}
          <div style={{ display: 'flex', background: '#030712', border: '1px solid #1f2937', borderRadius: '6px', padding: '2px', gap: '2px' }}>
             <button 
               onClick={() => setState(p => ({ ...p, view: 'code' }))} 
               className="btn-icon" 
               style={{ padding: '4px', background: view === 'code' ? '#1e293b' : 'transparent', color: view === 'code' ? '#3b82f6' : '#64748b' }}
               title="Editor View"
             >
               <Edit3 size={14} />
             </button>
             <button 
               onClick={() => setState(p => ({ ...p, view: 'split' }))} 
               className="btn-icon" 
               style={{ padding: '4px', background: view === 'split' ? '#1e293b' : 'transparent', color: view === 'split' ? '#3b82f6' : '#64748b' }}
               title="Split View"
             >
               <Columns size={14} />
             </button>
             <button 
               onClick={() => setState(p => ({ ...p, view: 'preview' }))} 
               className="btn-icon" 
               style={{ padding: '4px', background: view === 'preview' ? '#1e293b' : 'transparent', color: view === 'preview' ? '#3b82f6' : '#64748b' }}
               title="Preview Only"
             >
               <Eye size={14} />
             </button>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '9px', background: '#1e293b', padding: '4px 8px', borderRadius: '4px', color: '#94a3b8' }}>
            <Layers size={10} /> {allFiles.length}
          </div>

          <button 
