      const initialState: IDEState = {
        files: {
          js: parsed.js || parsed.code || '',
          html: parsed.html || '<div id="app"></div>',
          css: parsed.css || 'body { margin: 0; background: #000; color: #fff; }',
          singleHtml: parsed.singleHtml || '<!DOCTYPE html>\n<html>\n<head>\n  <meta charset="utf-8">\n</head>\n<body>\n  <h1>Hello World</h1>\n</body>\n</html>',
          mode: isSingle ? 'single' : 'multi'
        },
        isFullscreen: false, 
        view: 'split', 
        activeTab: isSingle ? 'singleHtml' : 'js'
      };
      ideStateStore[blockId] = initialState;
      return initialState;
