                transition: 'all 0.2s'
              }}
            >
              {tab.toUpperCase()}
            </button>
          )) : (
            <button 
              style={{ 
                padding: '0 14px', 
                background: '#030712',
                color: '#3b82f6', 
                border: 'none', 
                borderBottom: '2px solid #3b82f6', 
                fontSize: '11px', 
                fontWeight: 700, 
                flexShrink: 0 
              }}
