        </div>
      </div>

      {/* Tab bar - Below Controls */}
      <div style={{ height: '36px', background: '#111827', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', padding: '0 8px' }}>
        {files.mode === 'multi' ? (['js', 'html', 'css'] as const).map(tab => (
