      </div>

      {/* Editor Content Area */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden', background: '#000' }}>
        <div style={{ 
          flex: view === 'split' ? 1 : (view === 'code' ? 1 : 0), 
          display: view === 'preview' ? 'none' : 'block', 
          height: '100%', background: '#1e1e1e', 
          borderRight: view === 'split' ? '1px solid #1f2937' : 'none' 
        }}>
          <Editor 
            key={`${blockId}-${activeTab}`}
            height="100%" 
            theme="vs-dark" 
            language={activeTab === 'js' ? 'javascript' : (activeTab === 'css' ? 'css' : 'html')} 
            value={(files as any)[activeTab]} 
            onChange={handleEditorChange} 
            options={{ 
              fontSize: 13, minimap: { enabled: false }, scrollBeyondLastLine: false, padding: { top: 12 },
              automaticLayout: true, tabSize: 2, wordWrap: 'on'
            }} 
