        </div>
      </div>
    </div>
  );
});

import React, { useState, useEffect, useRef, useCallback } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, Edit3, Columns, Eye
} from 'lucide-react';
import { FileNode, NodeType } from '../../types';

interface CodeFiles {
  js: string; 
  html: string; 
  css: string; 
  singleHtml?: string; 
  mode: 'multi' | 'single';
  internal_block_id?: string;
}

interface IDEState {
  files: CodeFiles; 
  isFullscreen: boolean; 
  view: 'split' | 'code' | 'preview'; 
  activeTab: 'js' | 'html' | 'css' | 'singleHtml';
}

interface CodeEditorEngineProps {
  configStr: string; 
  onUpdate?: (newConfig: string) => void; 
  blockId: string; 
  allFiles?: FileNode[];
}

// Global UI state cache to preserve things like active tab/fullscreen across re-renders
const globalIdeStore: Record<string, IDEState> = {};

export const CodeEditorEngine = React.memo(({ configStr, onUpdate, blockId, allFiles = [] }: CodeEditorEngineProps) => {
  // 1. Determine initial state
  const getInitialState = (): IDEState => {
    // Return cached state if it exists for this specific unique ID
    if (globalIdeStore[blockId]) {
      return globalIdeStore[blockId];
    }

    let parsed: any = {};
    try { 
      parsed = JSON.parse(configStr); 
    } catch (e) {
      parsed = {};
    }

    const isSingle = parsed.mode === 'single';
    return {
      files: {
        js: parsed.js ?? '',
        html: parsed.html ?? '<div id="app"></div>',
        css: parsed.css ?? 'body { margin: 0; background: #000; color: #fff; }',
        singleHtml: parsed.singleHtml ?? '<!DOCTYPE html>\n<html>\n<body>\n  <h1>Hello World</h1>\n</body>\n</html>',
        mode: isSingle ? 'single' : 'multi',
        internal_block_id: blockId
      },
      isFullscreen: false, 
      view: 'split', 
      activeTab: isSingle ? 'singleHtml' : 'js'
    };
  };

  const [state, setState] = useState<IDEState>(getInitialState);
  const { files, isFullscreen, view, activeTab } = state;
  const [isCompiling, setIsCompiling] = useState(false);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);

  const iframeRef = useRef<HTMLIFrameElement>(null);
  const lastSyncConfig = useRef(configStr);
  const frameRafRef = useRef<number | null>(null);

  // Sync to global store whenever state changes so it survives markdown re-renders
  useEffect(() => {
    globalIdeStore[blockId] = state;
  }, [state, blockId]);

  const handleEditorChange = (value: string | undefined) => {
    const newVal = value || '';
    setState(prev => ({
      ...prev,
      files: { ...prev.files, [activeTab]: newVal } 
    }));
    setHasUnsavedChanges(true);
  };

  const toggleMode = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    const nextMode = files.mode === 'multi' ? 'single' : 'multi';
    const nextTab = nextMode === 'single' ? 'singleHtml' : 'js';

    setState(prev => ({
      ...prev,
      files: { ...prev.files, mode: nextMode },
      activeTab: nextTab
    }));
    setHasUnsavedChanges(true);
  };

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;

    if (frameRafRef.current) cancelAnimationFrame(frameRafRef.current);

    frameRafRef.current = requestAnimationFrame(() => {
      setIsCompiling(true);

      // Update the parent markdown with the current code state
      const newConfig = JSON.stringify(files, null, 2);
      if (onUpdate && newConfig !== lastSyncConfig.current) {
        onUpdate(newConfig);
        lastSyncConfig.current = newConfig;
      }

      setHasUnsavedChanges(false);

      // Inject project assets
      const assetMap: Record<string, string> = {};
      allFiles.forEach(node => { 
        if (node.type === NodeType.FILE) assetMap[node.name] = node.content; 
      });
      const generateAssetScript = `window.assets = ${JSON.stringify(assetMap)};`;

      let finalSource = '';
      if (files.mode === 'single') {
        const base = files.singleHtml || '';
        const scriptTag = `<script>${generateAssetScript}</script>`;
        finalSource = base.includes('<head>') ? base.replace('<head>', `<head>${scriptTag}`) : `${scriptTag}${base}`;
      } else {
        finalSource = `
          <!DOCTYPE html>
          <html>
            <head>
              <meta charset="utf-8">
              <script>${generateAssetScript}</script>
              <style>${files.css}\nbody { margin: 0; min-height: 100vh; background-color: white; color: black; font-family: sans-serif; }</style>
            </head>
            <body>
              ${files.html}
              <script type="module">
                try { ${files.js} } catch (err) {
                  console.error("Runtime Error:", err);
                  const d = document.createElement('div');
                  d.style = "color:red;font-family:monospace;padding:10px;background:#fff;border:1px solid red;position:fixed;inset:0;z-index:999";
                  d.innerText = err.message;
                  document.body.appendChild(d);
                }
              </script>
            </body>
          </html>
        `;
      }

      const doc = iframeRef.current?.contentDocument || iframeRef.current?.contentWindow?.document;
      if (doc) { 
        doc.open(); 
        doc.write(finalSource); 
        doc.close(); 
      }
      setIsCompiling(false);
    });
  }, [files, onUpdate, allFiles]);

  // Run initial compilation and on mode/view changes
  useEffect(() => { 
    const t = setTimeout(runCode, 200); 
    return () => {
      clearTimeout(t);
      if (frameRafRef.current) cancelAnimationFrame(frameRafRef.current);
    };
  }, [view, files.mode, runCode]);

  const containerStyle: React.CSSProperties = isFullscreen ? { 
    position: 'fixed', inset: 0, zIndex: 10000, background: '#030712', display: 'flex', flexDirection: 'column' 
  } : { 
    position: 'relative', background: '#111827', borderRadius: '12px', border: '1px solid #1f2937', height: '520px', width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1.5rem 0'
  };

  return (
    <div style={containerStyle} id={blockId} onClick={e => e.stopPropagation()}>
      <div style={{ height: '44px', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#0f172a', padding: '0 12px', flexShrink: 0 }}>
        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
          <div style={{ display: 'flex', background: '#020617', border: '1px solid #334155', borderRadius: '6px', padding: '2px', gap: '2px' }}>
             <button onClick={() => setState(p => ({ ...p, view: 'code' }))} style={{ padding: '4px', background: view === 'code' ? '#1e293b' : 'transparent', color: view === 'code' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Edit3 size={14}/></button>
             <button onClick={() => setState(p => ({ ...p, view: 'split' }))} style={{ padding: '4px', background: view === 'split' ? '#1e293b' : 'transparent', color: view === 'split' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Columns size={14}/></button>
             <button onClick={() => setState(p => ({ ...p, view: 'preview' }))} style={{ padding: '4px', background: view === 'preview' ? '#1e293b' : 'transparent', color: view === 'preview' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Eye size={14}/></button>
          </div>
          <div onClick={toggleMode} style={{ display: 'flex', alignItems: 'center', gap: '6px', background: '#020617', border: '1px solid #334155', padding: '2px 8px', borderRadius: '20px', cursor: 'pointer', userSelect: 'none' }}>
            <span style={{ fontSize: '9px', fontWeight: 800, color: files.mode === 'multi' ? '#3b82f6' : '#475569' }}>MULTI</span>
            <div style={{ width: '22px', height: '12px', background: '#1e293b', borderRadius: '10px', position: 'relative' }}>
              <div style={{ position: 'absolute', top: '2px', left: files.mode === 'multi' ? '2px' : '12px', width: '8px', height: '8px', background: files.mode === 'multi' ? '#3b82f6' : '#10b981', borderRadius: '50%', transition: 'left 0.2s' }} />
            </div>
            <span style={{ fontSize: '9px', fontWeight: 800, color: files.mode === 'single' ? '#10b981' : '#475569' }}>HTML</span>
          </div>
        </div>
        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
          <button onClick={runCode} disabled={isCompiling} style={{ background: hasUnsavedChanges ? '#3b82f6' : '#10b981', color: 'white', border: 'none', borderRadius: '6px', height: '28px', padding: '0 12px', fontSize: '11px', fontWeight: 800, cursor: 'pointer' }}>
            {isCompiling ? '...' : 'RUN'}
          </button>
          <button onClick={() => setState(p => ({ ...p, isFullscreen: !isFullscreen }))} style={{ padding: '6px', background: '#1e293b', border: 'none', borderRadius: '6px', color: 'white', cursor: 'pointer' }}>
            {isFullscreen ? <Minimize2 size={14}/> : <Maximize2 size={14}/>}
          </button>
        </div>
      </div>

      <div style={{ height: '36px', background: '#111827', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', padding: '0 8px', flexShrink: 0 }}>
        {files.mode === 'multi' ? (['js', 'html', 'css'] as const).map(tab => (
          <button key={tab} onClick={() => setState(p => ({ ...p, activeTab: tab }))} style={{ height: '100%', padding: '0 16px', background: 'transparent', color: activeTab === tab ? '#3b82f6' : '#64748b', border: 'none', borderBottom: activeTab === tab ? '2px solid #3b82f6' : 'none', fontSize: '11px', fontWeight: 700, cursor: 'pointer' }}>{tab.toUpperCase()}</button>
        )) : (
          <button style={{ height: '100%', padding: '0 16px', background: 'transparent', color: '#3b82f6', border: 'none', borderBottom: '2px solid #3b82f6', fontSize: '11px', fontWeight: 700 }}>HTML</button>
        )}
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden', background: '#000' }}>
        <div style={{ flex: view === 'split' ? 1 : (view === 'code' ? 1 : 0), display: view === 'preview' ? 'none' : 'block', height: '100%', background: '#1e1e1e', borderRight: view === 'split' ? '1px solid #1f2937' : 'none' }}>
          <Editor 
            key={`${blockId}-${activeTab}`} 
            height="100%" 
            theme="vs-dark" 
            language={activeTab === 'js' ? 'javascript' : (activeTab === 'css' ? 'css' : 'html')} 
            value={(files as any)[activeTab]} 
            onChange={handleEditorChange} 
            options={{ fontSize: 13, minimap: { enabled: false }, scrollBeyondLastLine: false, padding: { top: 12 }, automaticLayout: true, tabSize: 2, wordWrap: 'on' }} 
          />
        </div>
        <div style={{ flex: view === 'split' ? 1 : (view === 'preview' ? 1 : 0), display: view === 'code' ? 'none' : 'block', height: '100%', background: '#fff', position: 'relative' }}>
          <iframe ref={iframeRef} title={`IDE ${blockId}`} style={{ width: '100%', height: '100%', border: 'none', background: '#fff' }} />
        </div>
      </div>
    </div>
  );
});

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const contentRef = useRef(content);

  useEffect(() => {
    contentRef.current = content;
  }, [content]);

  const [localContent, setLocalContent] = useState(content);
  const debounceTimer = useRef<number | null>(null);

  useEffect(() => {
    setLocalContent(content);
  }, [content]);

  const handleTextareaChange = (val: string) => {
    setLocalContent(val);
    if (debounceTimer.current) window.clearTimeout(debounceTimer.current);
    debounceTimer.current = window.setTimeout(() => {
      onChange(val);
    }, 150);
  };

  const insertFormat = (prefix: string, suffix: string = '', block: boolean = false) => {
    if (!textareaRef.current) return;
    const { selectionStart: start, selectionEnd: end, value } = textareaRef.current;
    const selectedText = value.substring(start, end);

    let insertion = prefix + selectedText + suffix;
    if (block && value[start - 1] !== '\n' && start !== 0) {
      insertion = '\n' + insertion;
    }

    const newVal = value.substring(0, start) + insertion + value.substring(end);
    handleTextareaChange(newVal);

    setTimeout(() => {
      if (textareaRef.current) {
        textareaRef.current.focus();
        const cursorPosition = start + prefix.length + selectedText.length;
        textareaRef.current.selectionStart = textareaRef.current.selectionEnd = cursorPosition;
      }
    }, 0);
  };

  const handleIDEUpdate = useCallback((oldConfigStr: string, newConfigStr: string) => {
    const currentMarkdown = contentRef.current;

    let targetId: string | null = null;
    try {
      const parsed = JSON.parse(oldConfigStr);
      targetId = parsed.internal_block_id;
    } catch(e) {}

    if (!targetId) return;

    // Use a precise identifier to find the specific IDE block to replace
    const escapedId = targetId.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regex = new RegExp(`\`\`\`ide[\\s\\S]*?"internal_block_id":\\s*"${escapedId}"[\\s\\S]*?\`\`\``, 'g');

    const newMarkdown = currentMarkdown.replace(regex, `\`\`\`ide\n${newConfigStr}\n\`\`\``);

    if (newMarkdown !== currentMarkdown) {
      onChange(newMarkdown);
    }
  }, [onChange]);

  const markdownComponents = useMemo(() => {
    return {
      code({node, inline, className, children, ...props}: any) {
          const match = /language-([\w-]+)/.exec(className || '');
          const codeContent = String(children).replace(/\n$/, '');
          if (!inline) {
            switch (match?.[1]) {
              case 'mermaid': return <MermaidDiagram chart={codeContent} />;
              case 'smiles': return <SmilesDiagram smiles={codeContent} />;
              case 'plot': return <InteractivePlot configStr={codeContent} />;
              case 'physics': return <PhysicsSimulation configStr={codeContent} />;
              case 'ide': {
                let parsed;
                try { 
                  parsed = JSON.parse(codeContent); 
                } catch(e) { 
                  parsed = {}; 
                }

                // CRITICAL: Each IDE MUST have a stable unique ID to maintain its own state
                const blockId = parsed.internal_block_id || `ide-init-${Math.random().toString(36).substr(2, 9)}`;

                return (
                  <CodeEditorEngine 
                    key={blockId} // Stable key prevents remounts during markdown updates
                    blockId={blockId}
                    configStr={codeContent} 
                    allFiles={allNodes}
                    onUpdate={(newVal) => handleIDEUpdate(codeContent, newVal)}
                  />
                );
              }
            }
          }
          return <code className={className} {...props}>{children}</code>;
      },
      div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
      span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
    };
  }, [handleIDEUpdate, allNodes]);

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={localContent} 
                  onChange={e => handleTextareaChange(e.target.value)} 
                  onKeyDown={(e) => {
                    if (e.key === 'Tab') {
                      e.preventDefault();
                      const { selectionStart: start, selectionEnd: end, value } = e.currentTarget;
                      const newVal = value.substring(0, start) + '  ' + value.substring(end);
                      handleTextareaChange(newVal);
                      setTimeout(() => { if(textareaRef.current) textareaRef.current.selectionStart = textareaRef.current.selectionEnd = start + 2; }, 0);
                    }
                  }}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div id="markdown-preview" className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents}
                    >
                      {content}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { 
  Wand2, RotateCw, FlipHorizontal, Square, 
  Download, Image as ImageIcon, Loader2, Sparkles 
} from 'lucide-react';

interface ImageProcessorProps {
  src: string;
  onUpdate: (newSrc: string) => void;
  onClose: () => void;
}

export const ImageProcessor: React.FC<ImageProcessorProps> = ({ src, onUpdate, onClose }) => {
  const [currentSrc, setCurrentSrc] = useState(src);
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const applyFilter = (filter: string) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      ctx.filter = filter;
      ctx.drawImage(img, 0, 0);
      setCurrentSrc(canvas.toDataURL('image/png'));
      ctx.filter = 'none';
    };
    img.src = currentSrc;
  };

  const handleAiEdit = async () => {
    if (!aiPrompt.trim()) return;
    setIsProcessing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = currentSrc.split(',')[1];

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: 'image/png' } },
            { text: aiPrompt }
          ],
        },
      });

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          const newImage = `data:image/png;base64,${part.inlineData.data}`;
          setCurrentSrc(newImage);
          break;
        }
      }
    } catch (error) {
      console.error("AI processing failed:", error);
      alert("AI processing failed. Please check your prompt or API key.");
    } finally {
      setIsProcessing(false);
      setAiPrompt('');
    }
  };

  useEffect(() => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      if (canvasRef.current) {
        canvasRef.current.width = img.width;
        canvasRef.current.height = img.height;
        const ctx = canvasRef.current.getContext('2d');
        ctx?.drawImage(img, 0, 0);
      }
    };
    img.src = src;
  }, [src]);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-[#0f172a] border border-[#1e293b] rounded-xl w-full max-w-5xl h-[85vh] flex flex-col overflow-hidden shadow-2xl">
        <div className="p-4 border-b border-[#1e293b] flex justify-between items-center bg-[#111827]">
          <div className="flex items-center gap-2">
            <ImageIcon className="text-blue-500" size={20} />
            <span className="font-bold text-sm">IMAGE PROCESSOR</span>
          </div>
          <button onClick={onClose} className="p-1 hover:bg-white/10 rounded-md transition-colors">
            <Square size={18} className="rotate-45" />
          </button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* Main Viewport */}
          <div className="flex-1 bg-black/40 flex items-center justify-center p-8 overflow-auto relative">
            <canvas ref={canvasRef} className="max-w-full max-h-full object-contain shadow-lg rounded-sm" />
            {isProcessing && (
              <div className="absolute inset-0 bg-black/60 flex flex-col items-center justify-center gap-4 z-10">
                <Loader2 className="animate-spin text-blue-500" size={48} />
                <span className="text-blue-400 font-medium animate-pulse">AI is working...</span>
              </div>
