import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const contentRef = useRef(content);
  const [localContent, setLocalContent] = useState(content);

  // INVARIANT: Runtime execution state is stored here, NOT in the Markdown string during live editing.
  const ideStateRegistry = useRef<Record<string, string>>({});
  const debounceTimer = useRef<number | null>(null);

  useEffect(() => {
    if (content !== contentRef.current) {
      contentRef.current = content;
      setLocalContent(content);
      // Clean registry when switching files to prevent memory leaks or cross-file pollution
      ideStateRegistry.current = {};
    }
  }, [content, fileName]);

  /**
   * ATOMIC SERIALIZATION:
   * Only called when we need to persist the in-memory IDE states back to the Markdown source.
   * This happens on a longer debounce or explicit save event.
   */
  const persistChanges = useCallback(() => {
    const doc = contentRef.current;
    const registry = ideStateRegistry.current;

    const newDoc = doc.replace(/```ide\s*([\s\S]*?)\s*```/g, (fullMatch, blockContent) => {
      try {
        const parsed = JSON.parse(blockContent);
        const id = parsed.internal_block_id;
        if (id && registry[id]) {
          return `\`\`\`ide\n${registry[id]}\n\`\`\``;
        }
        return fullMatch;
      } catch (e) {
        return fullMatch;
      }
    });

    if (newDoc !== doc) {
      contentRef.current = newDoc;
      onChange(newDoc);
    }
  }, [onChange]);

  const handleTextareaChange = (val: string) => {
    setLocalContent(val);
    contentRef.current = val;
    if (debounceTimer.current) window.clearTimeout(debounceTimer.current);
    debounceTimer.current = window.setTimeout(() => {
      persistChanges();
    }, 1000);
  };

  const insertFormat = (prefix: string, suffix: string = '', block: boolean = false) => {
    if (!textareaRef.current) return;
    const { selectionStart: start, selectionEnd: end, value } = textareaRef.current;
    const selectedText = value.substring(start, end);

    let insertion = prefix + selectedText + suffix;
    if (block && value[start - 1] !== '\n' && start !== 0) {
      insertion = '\n' + insertion;
    }

    const newVal = value.substring(0, start) + insertion + value.substring(end);
    handleTextareaChange(newVal);

    setTimeout(() => {
      if (textareaRef.current) {
        textareaRef.current.focus();
        const cursorPosition = start + prefix.length + selectedText.length;
        textareaRef.current.selectionStart = textareaRef.current.selectionEnd = cursorPosition;
      }
    }, 0);
  };

  // Runtime updates now only touch the registry, never the Markdown source directly.
  const handleIDEUpdate = useCallback((targetId: string, newConfigStr: string) => {
    ideStateRegistry.current[targetId] = newConfigStr;
    // We do NOT call persistChanges() on every keystroke to prevent re-parse loops.
    // The registry remains the source of truth for the active session.
  }, []);

  const markdownComponents = useMemo(() => {
    return {
      code({node, inline, className, children, ...props}: any) {
          const match = /language-([\w-]+)/.exec(className || '');
          const codeContent = String(children).replace(/\n$/, '');
          if (!inline) {
            switch (match?.[1]) {
              case 'mermaid': return <MermaidDiagram chart={codeContent} />;
              case 'smiles': return <SmilesDiagram smiles={codeContent} />;
              case 'plot': return <InteractivePlot configStr={codeContent} />;
              case 'physics': return <PhysicsSimulation configStr={codeContent} />;
              case 'ide': {
                let parsed: any = {};
                try { 
                  parsed = JSON.parse(codeContent); 
                } catch(e) { 
                  return <pre>{codeContent}</pre>; 
                }

                const blockId = parsed.internal_block_id;
                if (!blockId) return <pre>{codeContent}</pre>;

                // We inject the runtime state from the registry if it exists, otherwise the source JSON.
                const configToUse = ideStateRegistry.current[blockId] || codeContent;

                return (
                  <CodeEditorEngine 
                    key={blockId}
                    blockId={blockId}
                    configStr={configToUse} 
                    allFiles={allNodes}
                    onUpdate={(newVal) => handleIDEUpdate(blockId, newVal)}
                  />
                );
              }
            }
          }
          return <code className={className} {...props}>{children}</code>;
      },
      div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
      span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
    };
  }, [handleIDEUpdate, allNodes]);

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={localContent} 
                  onChange={e => handleTextareaChange(e.target.value)} 
                  onBlur={persistChanges} // Persist when leaving the textarea
                  onKeyDown={(e) => {
                    if (e.key === 'Tab') {
                      e.preventDefault();
                      const { selectionStart: start, selectionEnd: end, value } = e.currentTarget;
                      const newVal = value.substring(0, start) + '  ' + value.substring(end);
                      handleTextareaChange(newVal);
                      setTimeout(() => { if(textareaRef.current) textareaRef.current.selectionStart = textareaRef.current.selectionEnd = start + 2; }, 0);
                    }
                  }}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div id="markdown-preview" className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        key={`${fileName}-${viewMode}`}
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents}
                    >
                      {localContent}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const contentRef = useRef(content);
  const [localContent, setLocalContent] = useState(content);

  // REGISTRY: Store runtime IDE content here to isolate from the Markdown source during live edits.
  // This prevents the "leak" where nth IDE updates overwrite n-1 IDE blocks due to regex drift.
  const ideRegistry = useRef<Record<string, string>>({});
  const persistTimer = useRef<number | null>(null);

  useEffect(() => {
    if (content !== contentRef.current) {
      contentRef.current = content;
      setLocalContent(content);
      // Clear registry on file switch to ensure fresh state
      ideRegistry.current = {};
    }
  }, [content, fileName]);

  // ATOMIC PERSISTENCE: Converts registry back to Markdown source safely
  const persistToMarkdown = useCallback(() => {
    const currentDoc = contentRef.current;
    const registry = ideRegistry.current;

    // Use a non-greedy mapping approach to replace blocks by ID
    const newDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = JSON.parse(inner);
        const id = parsed.internal_block_id;
        if (id && registry[id]) {
          return `\`\`\`ide\n${registry[id]}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (newDoc !== currentDoc) {
      contentRef.current = newDoc;
      onChange(newDoc);
    }
  }, [onChange]);

  const handleTextareaChange = (val: string) => {
    setLocalContent(val);
    contentRef.current = val;
    if (persistTimer.current) window.clearTimeout(persistTimer.current);
    persistTimer.current = window.setTimeout(persistToMarkdown, 1500);
  };

  const insertFormat = (prefix: string, suffix: string = '', block: boolean = false) => {
    if (!textareaRef.current) return;
    const { selectionStart: start, selectionEnd: end, value } = textareaRef.current;
    const selectedText = value.substring(start, end);
    let insertion = prefix + selectedText + suffix;
    if (block && value[start - 1] !== '\n' && start !== 0) insertion = '\n' + insertion;
    const newVal = value.substring(0, start) + insertion + value.substring(end);
    handleTextareaChange(newVal);
  };

  // UPDATER: Only touches the registry, ensuring the Markdown string remains stable while typing
  const handleIDEUpdate = useCallback((targetId: string, newConfigStr: string) => {
    ideRegistry.current[targetId] = newConfigStr;
    // Debounce the persistence to avoid re-parsing the whole document on every keypress
    if (persistTimer.current) window.clearTimeout(persistTimer.current);
    persistTimer.current = window.setTimeout(persistToMarkdown, 2000);
  }, [persistToMarkdown]);

  const markdownComponents = useMemo(() => ({
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        const codeContent = String(children).replace(/\n$/, '');
        if (!inline && match?.[1] === 'ide') {
          try { 
            const parsed = JSON.parse(codeContent);
            const blockId = parsed.internal_block_id;
            if (!blockId) return <pre>{codeContent}</pre>;

            // Use registry value if exists, otherwise source content
            const configToUse = ideRegistry.current[blockId] || codeContent;

            return (
              <CodeEditorEngine 
                key={blockId} // Stable key is vital for React to not swap instances
                blockId={blockId}
                configStr={configToUse} 
                allFiles={allNodes}
                onUpdate={(newVal) => handleIDEUpdate(blockId, newVal)}
              />
            );
          } catch(e) { 
            return <pre>{codeContent}</pre>; 
          }
        }

        // Handle other languages
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={codeContent} />;
            case 'smiles': return <SmilesDiagram smiles={codeContent} />;
            case 'plot': return <InteractivePlot configStr={codeContent} />;
            case 'physics': return <PhysicsSimulation configStr={codeContent} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    },
    div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
    span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
  }), [handleIDEUpdate, allNodes]);

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={localContent} 
                  onChange={e => handleTextareaChange(e.target.value)} 
                  onBlur={persistToMarkdown}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div id="markdown-preview" className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        key={fileName} // Reset state when changing files
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents}
                    >
                      {localContent}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, Edit3, Columns, Eye, Play
} from 'lucide-react';
import { FileNode, NodeType } from '../../types';

interface CodeFiles {
  js: string; 
  html: string; 
  css: string; 
  internal_block_id?: string;
}

interface IDEState {
  files: CodeFiles; 
  isFullscreen: boolean; 
  view: 'split' | 'code' | 'preview'; 
  activeTab: 'js' | 'html' | 'css';
}

interface CodeEditorEngineProps {
  configStr: string; 
  onUpdate?: (newConfig: string) => void; 
  blockId: string; 
  allFiles?: FileNode[];
}

export const CodeEditorEngine = React.memo(({ configStr, onUpdate, blockId, allFiles = [] }: CodeEditorEngineProps) => {
  // We use configStr as a seed, but manage local state to keep UI snappy
  const [state, setState] = useState<IDEState>(() => {
    let parsed: any = {};
    try { parsed = JSON.parse(configStr); } catch (e) { parsed = {}; }
    return {
      files: {
        js: parsed.js ?? '',
        html: parsed.html ?? '<div id="app"></div>',
        css: parsed.css ?? 'body { margin: 1rem; font-family: sans-serif; }',
        internal_block_id: blockId
      },
      isFullscreen: false, 
      view: 'split', 
      activeTab: 'js'
    };
  });

  const { files, isFullscreen, view, activeTab } = state;
  const [isCompiling, setIsCompiling] = useState(false);
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const runTimerRef = useRef<number | null>(null);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);

    const assetMap: Record<string, string> = {};
    allFiles.forEach(node => { 
      if (node.type === NodeType.FILE) assetMap[node.name] = node.content; 
    });

    // ISOLATION: Use unique window scopes and sandbox attributes to prevent cross-contamination
    const finalSource = `
      <!DOCTYPE html>
      <html lang="en">
        <head>
          <meta charset="utf-8">
          <style>
            ${files.css}
            body { margin: 0; min-height: 100vh; background: white; color: black; overflow: auto; }
          </style>
        </head>
        <body>
          <div id="ide-root-${blockId}">${files.html}</div>
          <script>
            window.assets = ${JSON.stringify(assetMap)};
            window.blockId = "${blockId}";
          </script>
          <script type="module">
            (function(scopedId) {
              try {
                ${files.js}
              } catch (err) {
                console.error("Runtime Error in IDE [" + scopedId + "]:", err);
              }
            })("${blockId}");
          </script>
        </body>
      </html>
    `;

    // Atomic update using srcdoc for best-in-class isolation
    iframeRef.current.srcdoc = finalSource;
    setTimeout(() => setIsCompiling(false), 250);
  }, [files, allFiles, blockId]);

  const handleEditorChange = (value: string | undefined) => {
    const newVal = value || '';
    setState(prev => {
      const updatedFiles = { ...prev.files, [activeTab]: newVal };

      // Debounce the notification to parent and the local preview run
      if (runTimerRef.current) window.clearTimeout(runTimerRef.current);
      runTimerRef.current = window.setTimeout(() => {
        if (onUpdate) onUpdate(JSON.stringify(updatedFiles, null, 2));
        runCode();
      }, 400);

      return { ...prev, files: updatedFiles };
    });
  };

  useEffect(() => {
    runCode();
    return () => { if (runTimerRef.current) window.clearTimeout(runTimerRef.current); };
  }, [blockId, runCode]);

  const containerStyle: React.CSSProperties = isFullscreen ? { 
    position: 'fixed', inset: 0, zIndex: 10000, background: '#030712', display: 'flex', flexDirection: 'column' 
  } : { 
    position: 'relative', background: '#111827', borderRadius: '12px', border: '1px solid #1f2937', height: '520px', width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1.5rem 0'
  };

  const memoizedEditor = useMemo(() => (
    <Editor 
      height="100%" 
      theme="vs-dark" 
      language={activeTab === 'js' ? 'javascript' : (activeTab === 'css' ? 'css' : 'html')} 
      value={(files as any)[activeTab]} 
      onChange={handleEditorChange} 
      onMount={(editor) => {
        requestAnimationFrame(() => editor.layout());
      }}
      options={{ 
        minimap: { enabled: false }, 
        automaticLayout: true, 
        fontSize: 12,
        scrollBeyondLastLine: false,
        wordWrap: 'on',
        fixedOverflowWidgets: true,
        fontFamily: 'JetBrains Mono, Menlo, Monaco, Consolas, monospace'
      }} 
    />
  ), [activeTab, blockId, files.js, files.html, files.css]);

  return (
    <div style={containerStyle} id={`container-${blockId}`} onClick={e => e.stopPropagation()}>
      <div style={{ height: '44px', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#0f172a', padding: '0 12px', flexShrink: 0 }}>
        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
          <div style={{ display: 'flex', background: '#020617', border: '1px solid #334155', borderRadius: '6px', padding: '2px', gap: '2px' }}>
             <button onClick={() => setState(p => ({ ...p, view: 'code' }))} style={{ padding: '4px', background: view === 'code' ? '#1e293b' : 'transparent', color: view === 'code' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Edit3 size={14}/></button>
             <button onClick={() => setState(p => ({ ...p, view: 'split' }))} style={{ padding: '4px', background: view === 'split' ? '#1e293b' : 'transparent', color: view === 'split' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Columns size={14}/></button>
             <button onClick={() => setState(p => ({ ...p, view: 'preview' }))} style={{ padding: '4px', background: view === 'preview' ? '#1e293b' : 'transparent', color: view === 'preview' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Eye size={14}/></button>
          </div>
          <span style={{ fontSize: '10px', color: '#64748b', marginLeft: '8px', fontWeight: 'bold' }}>BLOCK: {blockId.slice(0, 8)}</span>
        </div>
        <div style={{ display: 'flex', gap: '8px' }}>
          <button 
            onClick={(e) => { e.preventDefault(); runCode(); }} 
            disabled={isCompiling}
            className="btn-primary"
            style={{ padding: '4px 12px', fontSize: '11px', height: '28px', opacity: isCompiling ? 0.7 : 1 }}
          >
            {isCompiling ? '...' : 'RUN'}
          </button>
          <button onClick={() => setState(p => ({ ...p, isFullscreen: !isFullscreen }))} style={{ background: 'transparent', border: 'none', color: '#64748b', cursor: 'pointer' }}>
            {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
          </button>
        </div>
      </div>

      <div style={{ height: '32px', background: '#111827', borderBottom: '1px solid #1f2937', display: 'flex', gap: '4px', padding: '0 8px' }}>
        {(['js', 'html', 'css'] as const).map(tab => (
          <button 
            key={tab} 
            onClick={() => setState(p => ({ ...p, activeTab: tab }))} 
            style={{ 
              background: 'transparent', 
              color: activeTab === tab ? '#3b82f6' : '#64748b', 
              border: 'none', 
              borderBottom: activeTab === tab ? '2px solid #3b82f6' : 'none', 
              fontSize: '10px', fontWeight: 'bold', cursor: 'pointer', padding: '0 12px' 
            }}
          >
            {tab.toUpperCase()}
          </button>
        ))}
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        <div style={{ flex: view === 'split' ? 1 : (view === 'code' ? 1 : 0), display: view === 'preview' ? 'none' : 'block', height: '100%' }}>
          {memoizedEditor}
        </div>
        <div style={{ flex: view === 'split' ? 1 : (view === 'preview' ? 1 : 0), display: view === 'code' ? 'none' : 'block', height: '100%', background: '#fff' }}>
          <iframe 
            ref={iframeRef} 
            sandbox="allow-scripts"
            title={`Preview-${blockId}`} 
            style={{ width: '100%', height: '100%', border: 'none' }} 
          />
        </div>
      </div>
    </div>
  );
}, (prevProps, nextProps) => {
  // Only re-render if the blockId changed or config changed significantly
  return prevProps.blockId === nextProps.blockId && prevProps.configStr === nextProps.configStr;
});

import React, { useRef, useEffect, useState, useCallback } from 'react';
import mermaid from 'mermaid';
import { Maximize2, Minimize2, ZoomIn, ZoomOut, RefreshCw, Move } from 'lucide-react';

export const MermaidDiagram = ({ chart }: { chart: string }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgWrapperRef = useRef<HTMLDivElement>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [transform, setTransform] = useState({ x: 0, y: 0, scale: 1 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  // Initialize mermaid once
  useEffect(() => {
    mermaid.initialize({
      startOnLoad: false,
      securityLevel: 'loose',
      theme: 'dark',
      flowchart: {
        htmlLabels: false,
        useMaxWidth: true,
      },
    });
  }, []);

  useEffect(() => {
    let isMounted = true;

    const renderDiagram = async () => {
      // Safety check: Don't try to render if chart is empty or undefined
      if (!chart || !chart.trim() || !svgWrapperRef.current) return;

      try {
        const id = `mermaid-${Math.random().toString(36).substr(2, 9)}`;

        // requestAnimationFrame helps avoid "ResizeObserver loop limit exceeded" 
        // by ensuring layout work happens in the correct phase.
        requestAnimationFrame(async () => {
          if (!isMounted || !svgWrapperRef.current) return;

          try {
            const { svg } = await mermaid.render(id, chart.trim());
            if (isMounted && svgWrapperRef.current) {
              svgWrapperRef.current.innerHTML = svg;
              // Only reset transform on initial valid render
              setTransform({ x: 0, y: 0, scale: 1 });
            }
          } catch (err) {
            if (isMounted && svgWrapperRef.current) {
              console.error("Mermaid render error:", err);
              svgWrapperRef.current.innerHTML = `<div style="color:#f87171;font-size:0.75rem;padding:0.5rem;border:1px solid rgba(239,68,68,0.5);border-radius:0.25rem;background:rgba(127,29,29,0.1);font-family:monospace;white-space:pre-wrap">Syntax Error:\n${(err as Error).message}</div>`;
            }
          }
        });
      } catch (err) {
        console.error("Mermaid setup error:", err);
      }
    };

    renderDiagram();
    return () => { isMounted = false; };
  }, [chart]);

  const handleZoom = useCallback((delta: number) => {
    setTransform(prev => ({
      ...prev,
      scale: Math.max(0.1, Math.min(10, prev.scale + delta))
    }));
  }, []);

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        handleZoom(e.deltaY > 0 ? -0.1 : 0.1);
    }
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setDragStart({ x: e.clientX - transform.x, y: e.clientY - transform.y });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    setTransform(prev => ({
      ...prev,
      x: e.clientX - dragStart.x,
      y: e.clientY - dragStart.y
    }));
  };

  const handleMouseUp = () => setIsDragging(false);

  const toggleFullscreen = () => {
    setIsFullscreen(!isFullscreen);
    setTransform({ x: 0, y: 0, scale: 1 });
  };

  const resetView = () => setTransform({ x: 0, y: 0, scale: 1 });

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed',
    inset: 0,
    zIndex: 9999,
    backgroundColor: 'var(--bg-main)',
    display: 'flex',
    flexDirection: 'column',
    padding: '2rem'
  } : {
    position: 'relative',
    backgroundColor: 'var(--bg-sidebar)',
    borderRadius: '0.5rem',
    border: '1px solid var(--border-color)',
    height: '400px',
    width: '100%',
    display: 'flex',
    flexDirection: 'column',
    overflow: 'hidden',
    justifyContent: 'center'
  };

  return (
    <div 
        ref={containerRef} 
        style={containerStyle}
        onWheel={handleWheel}
        className="mermaid-interactive-container group"
    >
      <div style={{ 
          position: 'absolute', 
          top: '0.75rem', 
          right: '0.75rem', 
          display: 'flex', 
          gap: '0.5rem', 
          zIndex: 10,
          backgroundColor: 'rgba(0,0,0,0.6)',
          padding: '0.35rem',
          borderRadius: '0.5rem',
          backdropFilter: 'blur(8px)',
          border: '1px solid rgba(255,255,255,0.1)'
      }}>
        <button onClick={() => handleZoom(0.2)} className="btn-icon" title="Zoom In"><ZoomIn size={16}/></button>
        <button onClick={() => handleZoom(-0.2)} className="btn-icon" title="Zoom Out"><ZoomOut size={16}/></button>
        <button onClick={resetView} className="btn-icon" title="Reset View"><RefreshCw size={16}/></button>
        <div style={{ width: '1px', backgroundColor: 'rgba(255,255,255,0.2)', margin: '0 0.25rem' }} />
        <button onClick={toggleFullscreen} className="btn-icon" title={isFullscreen ? "Exit Fullscreen" : "Fullscreen"}>
          {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
        </button>
      </div>

      <div 
        style={{ 
            flex: 1, 
            cursor: isDragging ? 'grabbing' : 'grab',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            overflow: 'hidden'
        }}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
      >
        <div 
          ref={svgWrapperRef}
          style={{ 
              transform: `translate(${transform.x}px, ${transform.y}px) scale(${transform.scale})`,
              transition: isDragging ? 'none' : 'transform 0.1s ease-out',
              transformOrigin: 'center center',
              width: '100%',
              display: 'flex',
              justifyContent: 'center'
          }}
        />
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, Edit3, Columns, Eye, Play
} from 'lucide-react';
import { FileNode, NodeType } from '../../types';

// Global error handler to suppress the ResizeObserver loop limit exceeded notification
// This is common in complex layouts with editors and split panes.
if (typeof window !== 'undefined') {
  const resizeObserverError = /ResizeObserver loop limit exceeded|ResizeObserver loop completed with undelivered notifications/;
  const originalError = window.onerror;
  window.onerror = (message, source, lineno, colno, error) => {
    if (typeof message === 'string' && resizeObserverError.test(message)) {
      return true;
    }
    if (originalError) {
      return originalError(message, source, lineno, colno, error);
    }
    return false;
  };
}

interface CodeFiles {
  js: string; 
  html: string; 
  css: string; 
  internal_block_id?: string;
}

interface IDEState {
  files: CodeFiles; 
  isFullscreen: boolean; 
  view: 'split' | 'code' | 'preview'; 
  activeTab: 'js' | 'html' | 'css';
}

interface CodeEditorEngineProps {
  configStr: string; 
  onUpdate?: (newConfig: string) => void; 
  blockId: string; 
  allFiles?: FileNode[];
}

export const CodeEditorEngine = React.memo(({ configStr, onUpdate, blockId, allFiles = [] }: CodeEditorEngineProps) => {
  const [state, setState] = useState<IDEState>(() => {
    let parsed: any = {};
    try { parsed = JSON.parse(configStr); } catch (e) { parsed = {}; }
    return {
      files: {
        js: parsed.js ?? '',
        html: parsed.html ?? '<div id="app"></div>',
        css: parsed.css ?? 'body { margin: 1rem; font-family: sans-serif; }',
        internal_block_id: blockId
      },
      isFullscreen: false, 
      view: 'split', 
      activeTab: 'js'
    };
  });

  const { files, isFullscreen, view, activeTab } = state;
  const [isCompiling, setIsCompiling] = useState(false);
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const runTimerRef = useRef<number | null>(null);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);

    const assetMap: Record<string, string> = {};
    allFiles.forEach(node => { 
      if (node.type === NodeType.FILE) assetMap[node.name] = node.content; 
    });

    const finalSource = `
      <!DOCTYPE html>
      <html lang="en">
        <head>
          <meta charset="utf-8">
          <style>
            ${files.css}
            body { margin: 0; min-height: 100vh; background: white; color: black; overflow: auto; }
          </style>
        </head>
        <body>
          <div id="ide-root-${blockId}">${files.html}</div>
          <script>
            window.assets = ${JSON.stringify(assetMap)};
            window.blockId = "${blockId}";
          </script>
          <script type="module">
            (function(scopedId) {
              try {
                ${files.js}
              } catch (err) {
                console.error("Runtime Error in IDE [" + scopedId + "]:", err);
              }
            })("${blockId}");
          </script>
        </body>
      </html>
    `;

    iframeRef.current.srcdoc = finalSource;
    setTimeout(() => setIsCompiling(false), 250);
  }, [files, allFiles, blockId]);

  const handleEditorChange = (value: string | undefined) => {
    const newVal = value || '';
    setState(prev => {
      const updatedFiles = { ...prev.files, [activeTab]: newVal };

      if (runTimerRef.current) window.clearTimeout(runTimerRef.current);
      runTimerRef.current = window.setTimeout(() => {
        if (onUpdate) onUpdate(JSON.stringify(updatedFiles, null, 2));
        runCode();
      }, 400);

      return { ...prev, files: updatedFiles };
    });
  };

  useEffect(() => {
    runCode();
    return () => { if (runTimerRef.current) window.clearTimeout(runTimerRef.current); };
  }, [blockId, runCode]);

  const containerStyle: React.CSSProperties = isFullscreen ? { 
    position: 'fixed', inset: 0, zIndex: 10000, background: '#030712', display: 'flex', flexDirection: 'column' 
  } : { 
    position: 'relative', background: '#111827', borderRadius: '12px', border: '1px solid #1f2937', height: '520px', width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1.5rem 0'
  };

  const memoizedEditor = useMemo(() => (
    <Editor 
      height="100%" 
      theme="vs-dark" 
      language={activeTab === 'js' ? 'javascript' : (activeTab === 'css' ? 'css' : 'html')} 
      value={(files as any)[activeTab]} 
      onChange={handleEditorChange} 
      onMount={(editor) => {
        requestAnimationFrame(() => editor.layout());
      }}
      options={{ 
        minimap: { enabled: false }, 
        automaticLayout: true, 
        fontSize: 12,
        scrollBeyondLastLine: false,
        wordWrap: 'on',
        fixedOverflowWidgets: true,
        fontFamily: 'JetBrains Mono, Menlo, Monaco, Consolas, monospace'
      }} 
    />
  ), [activeTab, blockId, files.js, files.html, files.css]);

  return (
    <div style={containerStyle} id={`container-${blockId}`} onClick={e => e.stopPropagation()}>
      <div style={{ height: '44px', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#0f172a', padding: '0 12px', flexShrink: 0 }}>
        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
          <div style={{ display: 'flex', background: '#020617', border: '1px solid #334155', borderRadius: '6px', padding: '2px', gap: '2px' }}>
             <button onClick={() => setState(p => ({ ...p, view: 'code' }))} style={{ padding: '4px', background: view === 'code' ? '#1e293b' : 'transparent', color: view === 'code' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Edit3 size={14}/></button>
             <button onClick={() => setState(p => ({ ...p, view: 'split' }))} style={{ padding: '4px', background: view === 'split' ? '#1e293b' : 'transparent', color: view === 'split' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Columns size={14}/></button>
             <button onClick={() => setState(p => ({ ...p, view: 'preview' }))} style={{ padding: '4px', background: view === 'preview' ? '#1e293b' : 'transparent', color: view === 'preview' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Eye size={14}/></button>
          </div>
          <span style={{ fontSize: '10px', color: '#64748b', marginLeft: '8px', fontWeight: 'bold' }}>BLOCK: {blockId.slice(0, 8)}</span>
        </div>
        <div style={{ display: 'flex', gap: '8px' }}>
          <button 
            onClick={(e) => { e.preventDefault(); runCode(); }} 
            disabled={isCompiling}
            className="btn-primary"
            style={{ padding: '4px 12px', fontSize: '11px', height: '28px', opacity: isCompiling ? 0.7 : 1 }}
          >
            {isCompiling ? '...' : 'RUN'}
          </button>
          <button onClick={() => setState(p => ({ ...p, isFullscreen: !isFullscreen }))} style={{ background: 'transparent', border: 'none', color: '#64748b', cursor: 'pointer' }}>
            {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
          </button>
        </div>
      </div>

      <div style={{ height: '32px', background: '#111827', borderBottom: '1px solid #1f2937', display: 'flex', gap: '4px', padding: '0 8px' }}>
        {(['js', 'html', 'css'] as const).map(tab => (
          <button 
            key={tab} 
            onClick={() => setState(p => ({ ...p, activeTab: tab }))} 
            style={{ 
              background: 'transparent', 
              color: activeTab === tab ? '#3b82f6' : '#64748b', 
              border: 'none', 
              borderBottom: activeTab === tab ? '2px solid #3b82f6' : 'none', 
              fontSize: '10px', fontWeight: 'bold', cursor: 'pointer', padding: '0 12px' 
            }}
          >
            {tab.toUpperCase()}
          </button>
        ))}
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        <div style={{ flex: view === 'split' ? 1 : (view === 'code' ? 1 : 0), display: view === 'preview' ? 'none' : 'block', height: '100%' }}>
          {memoizedEditor}
        </div>
        <div style={{ flex: view === 'split' ? 1 : (view === 'preview' ? 1 : 0), display: view === 'code' ? 'none' : 'block', height: '100%', background: '#fff' }}>
          <iframe 
            ref={iframeRef} 
            sandbox="allow-scripts"
            title={`Preview-${blockId}`} 
            style={{ width: '100%', height: '100%', border: 'none' }} 
          />
        </div>
      </div>
    </div>
  );
}, (prevProps, nextProps) => {
  return prevProps.blockId === nextProps.blockId && prevProps.configStr === nextProps.configStr;
});

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const contentRef = useRef(content);
  const [localContent, setLocalContent] = useState(content);

  // REGISTRY: Store runtime IDE content here to isolate from the Markdown source during live edits.
  const ideRegistry = useRef<Record<string, string>>({});
  const persistTimer = useRef<number | null>(null);

  useEffect(() => {
    if (content !== contentRef.current) {
      contentRef.current = content;
      setLocalContent(content);
      // Clear registry on file switch to ensure fresh state
      ideRegistry.current = {};
    }
  }, [content, fileName]);

  // ATOMIC PERSISTENCE: Converts registry back to Markdown source safely
  const persistToMarkdown = useCallback(() => {
    const currentDoc = contentRef.current;
    const registry = ideRegistry.current;

    const newDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = JSON.parse(inner);
        const id = parsed.internal_block_id;
        if (id && registry[id]) {
          return `\`\`\`ide\n${registry[id]}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (newDoc !== currentDoc) {
      contentRef.current = newDoc;
      setLocalContent(newDoc); // Keep the textarea in sync with the persisted state
      onChange(newDoc);
    }
  }, [onChange]);

  const handleTextareaChange = (val: string) => {
    setLocalContent(val);
    contentRef.current = val;
    if (persistTimer.current) window.clearTimeout(persistTimer.current);
    persistTimer.current = window.setTimeout(persistToMarkdown, 1500);
  };

  const insertFormat = (prefix: string, suffix: string = '', block: boolean = false) => {
    if (!textareaRef.current) return;
    const { selectionStart: start, selectionEnd: end, value } = textareaRef.current;
    const selectedText = value.substring(start, end);
    let insertion = prefix + selectedText + suffix;
    if (block && value[start - 1] !== '\n' && start !== 0) insertion = '\n' + insertion;
    const newVal = value.substring(0, start) + insertion + value.substring(end);
    handleTextareaChange(newVal);
  };

  // UPDATER: Only touches the registry to keep preview fast, then schedules a source sync.
  const handleIDEUpdate = useCallback((targetId: string, newConfigStr: string) => {
    ideRegistry.current[targetId] = newConfigStr;

    // We update the local content immediately so the user sees the change in the editor tab
    // but we use the ref for the actual transformation logic to avoid race conditions.
    const registry = ideRegistry.current;
    const currentDoc = contentRef.current;

    // We update the local state so the TEXTAREA is not stale
    const updatedDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = JSON.parse(inner);
        const id = parsed.internal_block_id;
        if (id === targetId) {
          return `\`\`\`ide\n${newConfigStr}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (updatedDoc !== currentDoc) {
      contentRef.current = updatedDoc;
      setLocalContent(updatedDoc);
    }

    // Debounce the notification to parent state (expensive)
    if (persistTimer.current) window.clearTimeout(persistTimer.current);
    persistTimer.current = window.setTimeout(() => {
      onChange(contentRef.current);
    }, 2000);
  }, [onChange]);

  const markdownComponents = useMemo(() => ({
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        const codeContent = String(children).replace(/\n$/, '');
        if (!inline && match?.[1] === 'ide') {
          try { 
            const parsed = JSON.parse(codeContent);
            const blockId = parsed.internal_block_id;
            if (!blockId) return <pre>{codeContent}</pre>;

            // Use registry value if exists, otherwise source content
            const configToUse = ideRegistry.current[blockId] || codeContent;

            return (
              <CodeEditorEngine 
                key={blockId} 
                blockId={blockId}
                configStr={configToUse} 
                allFiles={allNodes}
                onUpdate={(newVal) => handleIDEUpdate(blockId, newVal)}
              />
            );
          } catch(e) { 
            return <pre>{codeContent}</pre>; 
          }
        }

        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={codeContent} />;
            case 'smiles': return <SmilesDiagram smiles={codeContent} />;
            case 'plot': return <InteractivePlot configStr={codeContent} />;
            case 'physics': return <PhysicsSimulation configStr={codeContent} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    },
    div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
    span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
  }), [handleIDEUpdate, allNodes]);

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={localContent} 
                  onChange={e => handleTextareaChange(e.target.value)} 
                  onBlur={persistToMarkdown}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div id="markdown-preview" className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        key={`${fileName}-${viewMode}`} 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents}
                    >
                      {localContent}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

