            // Registry acts as the localized source of truth for runtime
            const configToUse = ideRegistry.current[blockId] || codeContent;

            return (
              <CodeEditorEngine 
                key={blockId} 
                blockId={blockId}
                configStr={configToUse} 
                allFiles={allNodes}
                onUpdate={(newVal) => handleIDEUpdate(blockId, newVal)}
              />
            );
