             <button onClick={() => setUiState(p => ({ ...p, view: 'split' }))} style={{ padding: '4px', background: uiState.view === 'split' ? '#1e293b' : 'transparent', color: uiState.view === 'split' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Columns size={14}/></button>
             <button onClick={() => setUiState(p => ({ ...p, view: 'preview' }))} style={{ padding: '4px', background: uiState.view === 'preview' ? '#1e293b' : 'transparent', color: uiState.view === 'preview' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Eye size={14}/></button>
          </div>
          <span style={{ fontSize: '10px', color: '#64748b', marginLeft: '8px', fontWeight: 'bold' }}>BLOCK: {blockId.slice(0, 8)}</span>
        </div>
        <div style={{ display: 'flex', gap: '8px' }}>
          <button 
            onClick={(e) => { e.preventDefault(); runCode(); }} 
            disabled={isCompiling}
            className="btn-primary"
            style={{ padding: '4px 12px', fontSize: '11px', height: '28px', opacity: isCompiling ? 0.7 : 1 }}
          >
            {isCompiling ? '...' : 'RUN'}
