import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Maximize2, Minimize2, Edit3, Columns, Eye
} from 'lucide-react';
import { FileNode, NodeType } from '../../types';

if (typeof window !== 'undefined') {
  const resizeObserverError = /ResizeObserver loop limit exceeded|ResizeObserver loop completed with undelivered notifications/;
  const originalError = window.onerror;
  window.onerror = (message, source, lineno, colno, error) => {
    if (typeof message === 'string' && resizeObserverError.test(message)) {
      return true;
    }
    if (originalError) {
      return originalError(message, source, lineno, colno, error);
    }
    return false;
  };
}

interface CodeFiles {
  js: string; 
  html: string; 
  css: string; 
  internal_block_id?: string;
}

interface CodeEditorEngineProps {
  configStr: string; 
  onUpdate?: (newFiles: CodeFiles) => void; 
  blockId: string; 
  allFiles?: FileNode[];
}

export const CodeEditorEngine = React.memo(({ configStr, onUpdate, blockId, allFiles = [] }: CodeEditorEngineProps) => {
  const currentFiles = useMemo(() => {
    try {
      const parsed = JSON.parse(configStr);
      return {
        js: parsed.js ?? '',
        html: parsed.html ?? '<div id="app"></div>',
        css: parsed.css ?? 'body { margin: 1rem; font-family: sans-serif; }',
        internal_block_id: blockId
      };
    } catch (e) {
      return { js: '', html: '', css: '', internal_block_id: blockId };
    }
  }, [configStr, blockId]);

  const [uiState, setUiState] = useState<{
    isFullscreen: boolean;
    view: 'split' | 'code' | 'preview';
    activeTab: 'js' | 'html' | 'css';
  }>({
    isFullscreen: false,
    view: 'split',
    activeTab: 'js'
  });

  const [isCompiling, setIsCompiling] = useState(false);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const runCode = useCallback(() => {
    if (!iframeRef.current) return;
    setIsCompiling(true);

    const assetMap: Record<string, string> = {};
    allFiles.forEach(node => { 
      if (node.type === NodeType.FILE) assetMap[node.name] = node.content; 
    });

    const finalSource = `
      <!DOCTYPE html>
      <html lang="en">
        <head>
          <meta charset="utf-8">
          <style>
            ${currentFiles.css}
            body { margin: 0; min-height: 100vh; background: white; color: black; overflow: auto; }
          </style>
        </head>
        <body>
          <div id="ide-root-${blockId}">${currentFiles.html}</div>
          <script>
            window.assets = ${JSON.stringify(assetMap)};
            window.blockId = "${blockId}";
          </script>
          <script type="module">
            (function(scopedId) {
              try {
                ${currentFiles.js}
              } catch (err) {
                console.error("Runtime Error in IDE [" + scopedId + "]:", err);
              }
            })("${blockId}");
          </script>
        </body>
      </html>
    `;

    iframeRef.current.srcdoc = finalSource;
    setTimeout(() => setIsCompiling(false), 250);
  }, [currentFiles, allFiles, blockId]);

  const handleContentChange = (value: string | undefined) => {
    const newVal = value || '';
    const updatedFiles = { ...currentFiles, [uiState.activeTab]: newVal };
    if (onUpdate) {
      onUpdate(updatedFiles);
    }
  };

  useEffect(() => {
    runCode();
  }, [runCode]);

  const containerStyle: React.CSSProperties = uiState.isFullscreen ? { 
    position: 'fixed', inset: 0, zIndex: 10000, background: '#030712', display: 'flex', flexDirection: 'column' 
  } : { 
    position: 'relative', background: '#111827', borderRadius: '12px', border: '1px solid #1f2937', height: '520px', width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', margin: '1.5rem 0'
  };

  return (
    <div style={containerStyle} id={`container-${blockId}`} onClick={e => e.stopPropagation()}>
      <div style={{ height: '44px', borderBottom: '1px solid #1f2937', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#0f172a', padding: '0 12px', flexShrink: 0 }}>
        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
          <div style={{ display: 'flex', background: '#020617', border: '1px solid #334155', borderRadius: '6px', padding: '2px', gap: '2px' }}>
             <button onClick={() => setUiState(p => ({ ...p, view: 'code' }))} style={{ padding: '4px', background: uiState.view === 'code' ? '#1e293b' : 'transparent', color: uiState.view === 'code' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Edit3 size={14}/></button>
             <button onClick={() => setUiState(p => ({ ...p, view: 'split' }))} style={{ padding: '4px', background: uiState.view === 'split' ? '#1e293b' : 'transparent', color: uiState.view === 'split' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Columns size={14}/></button>
             <button onClick={() => setUiState(p => ({ ...p, view: 'preview' }))} style={{ padding: '4px', background: uiState.view === 'preview' ? '#1e293b' : 'transparent', color: uiState.view === 'preview' ? '#3b82f6' : '#64748b', border: 'none', borderRadius: '4px', cursor: 'pointer' }}><Eye size={14}/></button>
          </div>
          <span style={{ fontSize: '10px', color: '#64748b', marginLeft: '8px', fontWeight: 'bold' }}>BLOCK: {blockId.slice(0, 8)}</span>
        </div>
        <div style={{ display: 'flex', gap: '8px' }}>
          <button 
            onClick={(e) => { e.preventDefault(); runCode(); }} 
            disabled={isCompiling}
            className="btn-primary"
            style={{ padding: '4px 12px', fontSize: '11px', height: '28px', opacity: isCompiling ? 0.7 : 1 }}
          >
            {isCompiling ? '...' : 'RUN'}
          </button>
          <button onClick={() => setUiState(p => ({ ...p, isFullscreen: !uiState.isFullscreen }))} style={{ background: 'transparent', border: 'none', color: '#64748b', cursor: 'pointer' }}>
            {uiState.isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
          </button>
        </div>
      </div>

      <div style={{ height: '32px', background: '#111827', borderBottom: '1px solid #1f2937', display: 'flex', gap: '4px', padding: '0 8px' }}>
        {(['js', 'html', 'css'] as const).map(tab => (
          <button 
            key={tab} 
            onClick={() => setUiState(p => ({ ...p, activeTab: tab }))} 
            style={{ 
              background: 'transparent', 
              color: uiState.activeTab === tab ? '#3b82f6' : '#64748b', 
              border: 'none', 
              borderBottom: uiState.activeTab === tab ? '2px solid #3b82f6' : 'none', 
              fontSize: '10px', fontWeight: 'bold', cursor: 'pointer', padding: '0 12px' 
            }}
          >
            {tab.toUpperCase()}
          </button>
        ))}
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        <div style={{ flex: uiState.view === 'split' ? 1 : (uiState.view === 'code' ? 1 : 0), display: uiState.view === 'preview' ? 'none' : 'block', height: '100%' }}>
          <Editor 
            height="100%" 
            theme="vs-dark" 
            language={uiState.activeTab === 'js' ? 'javascript' : (uiState.activeTab === 'css' ? 'css' : 'html')} 
            value={(currentFiles as any)[uiState.activeTab]} 
            onChange={handleContentChange} 
            onMount={(editor) => {
              requestAnimationFrame(() => editor.layout());
            }}
            options={{ 
              minimap: { enabled: false }, 
              automaticLayout: true, 
              fontSize: 12,
              scrollBeyondLastLine: false,
              wordWrap: 'on',
              fixedOverflowWidgets: true,
              fontFamily: 'JetBrains Mono, Menlo, Monaco, Consolas, monospace'
            }} 
          />
        </div>
        <div style={{ flex: uiState.view === 'split' ? 1 : (uiState.view === 'preview' ? 1 : 0), display: uiState.view === 'code' ? 'none' : 'block', height: '100%', background: '#fff' }}>
          <iframe 
            ref={iframeRef} 
            sandbox="allow-scripts"
            title={`Preview-${blockId}`} 
            style={{ width: '100%', height: '100%', border: 'none' }} 
          />
        </div>
      </div>
    </div>
  );
}, (prevProps, nextProps) => {
  return prevProps.blockId === nextProps.blockId && prevProps.configStr === nextProps.configStr;
});

